205→    pub fn set_changes(&mut self, changes: Vec<Change>) {
206→        // Build selectable indices (non graph-only lines)
207→        self.selectable_indices = changes
208→            .iter()
209→            .enumerate()
210→            .filter(|(_, c)| !c.is_graph_only)
211→            .map(|(i, _)| i)
212→            .collect();
