232→    /// Move selection down (skips graph-only lines)
233→    pub fn move_down(&mut self) {
234→        if self.selection_cursor < self.selectable_indices.len().saturating_sub(1) {
235→            self.selection_cursor += 1;
236→            self.selected_index = self.selectable_indices[self.selection_cursor];
237→        }
