344→    /// Start squash destination selection mode
345→    ///
346→    /// Returns true if mode was entered, false if no change is selected.
347→    pub fn start_squash_select(&mut self) -> bool {
348→        // Clone change_id first to avoid borrow conflict
349→        let change_id = self.selected_change().map(|c| c.change_id.clone());
350→
351→        if let Some(change_id) = change_id {
352→            self.squash_source = Some(change_id);
353→            self.input_mode = InputMode::SquashSelect;
354→            true
355→        } else {
356→            false
357→        }
358→    }
359→
360→    /// Cancel squash selection mode
361→    pub fn cancel_squash_select(&mut self) {
