363→        self.input_mode = InputMode::Normal;
364→    }
365→
366→    /// Start compare revision selection mode
367→    ///
368→    /// The currently selected change becomes the "from" revision.
369→    /// The user then selects the "to" revision.
370→    /// Returns true if mode was entered, false if no change is selected.
371→    pub fn start_compare_select(&mut self) -> bool {
372→        let change_id = self.selected_change().map(|c| c.change_id.clone());
373→
374→        if let Some(change_id) = change_id {
375→            self.compare_from = Some(change_id);
376→            self.input_mode = InputMode::CompareSelect;
377→            true
378→        } else {
379→            false
380→        }
381→    }
382→
383→    /// Cancel compare selection mode
384→    pub fn cancel_compare_select(&mut self) {
385→        self.compare_from = None;
386→        self.input_mode = InputMode::Normal;
387→    }
388→
389→    /// Start parallelize selection mode
390→    ///
391→    /// The currently selected change becomes the "from" revision.
392→    /// The user then selects the "to" revision to define the range.
393→    /// Returns true if mode was entered, false if no change is selected.
394→    pub fn start_parallelize_select(&mut self) -> bool {
395→        let change_id = self.selected_change().map(|c| c.change_id.clone());
396→
397→        if let Some(change_id) = change_id {
398→            self.parallelize_from = Some(change_id);
399→            self.input_mode = InputMode::ParallelizeSelect;
400→            true
401→        } else {
402→            false
403→        }
404→    }
405→
406→    /// Cancel parallelize selection mode
407→    pub fn cancel_parallelize_select(&mut self) {
408→        self.parallelize_from = None;
409→        self.input_mode = InputMode::Normal;
410→    }
411→
412→    /// Select a change by its change_id (exact match)
413→    ///
414→    /// Returns true if the change was found and selected, false otherwise.
415→    /// The scroll_offset will be updated during next render via calculate_scroll_offset().
416→    pub fn select_change_by_id(&mut self, change_id: &str) -> bool {
417→        // Find the change in the selectable indices
418→        for (cursor, &idx) in self.selectable_indices.iter().enumerate() {
419→            if let Some(change) = self.changes.get(idx)
420→                && change.change_id == change_id
421→            {
422→                self.selection_cursor = cursor;
423→                self.selected_index = idx;
424→                return true;
425→            }
426→        }
427→        false
428→    }
429→
430→    /// Get the current selection cursor position (index into selectable_indices)
431→    pub fn selected_selectable_index(&self) -> usize {
432→        self.selection_cursor
433→    }
434→
435→    /// Select the working copy (@) change
436→    ///
437→    /// Searches for the change with `is_working_copy == true` and moves
438→    /// the cursor to it. Used after `jj next`/`jj prev` to follow @.
439→    /// Returns true if working copy was found and selected.
440→    pub fn select_working_copy(&mut self) -> bool {
441→        for (cursor, &idx) in self.selectable_indices.iter().enumerate() {
442→            if let Some(change) = self.changes.get(idx)
443→                && change.is_working_copy
444→            {
445→                self.selection_cursor = cursor;
446→                self.selected_index = idx;
447→                return true;
448→            }
449→        }
450→        false
451→    }
452→
453→    /// Select a change by prefix match on change_id
454→    ///
455→    /// Used when the caller has a potentially shorter change_id (e.g., from
456→    /// `jj file annotate` which uses `shortest()` format instead of `short(8)`).
457→    pub fn select_change_by_prefix(&mut self, prefix: &str) -> bool {
458→        for (cursor, &idx) in self.selectable_indices.iter().enumerate() {
459→            if let Some(change) = self.changes.get(idx)
460→                && change.change_id.starts_with(prefix)
461→            {
462→                self.selection_cursor = cursor;
463→                self.selected_index = idx;
464→                return true;
465→            }
466→        }
467→        false
468→    }
469→}
470→
