 18→impl LogView {
 19→    // ─────────────────────────────────────────────────────────────────────────
 20→    // Input handling
 21→    // ─────────────────────────────────────────────────────────────────────────
 22→
 23→    /// Handle key event and return action
 24→    pub fn handle_key(&mut self, key: KeyEvent) -> LogAction {
 25→        match self.input_mode {
 26→            InputMode::Normal => self.handle_normal_key(key),
 27→            InputMode::SearchInput => self.handle_search_input_key(key),
 28→            InputMode::RevsetInput => self.handle_revset_input_key(key),
 29→            InputMode::DescribeInput => self.handle_describe_input_key(key),
 30→            InputMode::BookmarkInput => self.handle_bookmark_input_key(key),
 31→            InputMode::RebaseModeSelect => self.handle_rebase_mode_select_key(key),
 32→            InputMode::RebaseSelect => self.handle_rebase_select_key(key),
 33→            InputMode::SquashSelect => self.handle_squash_select_key(key),
 34→            InputMode::CompareSelect => self.handle_compare_select_key(key),
 35→            InputMode::ParallelizeSelect => self.handle_parallelize_select_key(key),
 36→        }
 37→    }
 38→
 39→    fn handle_normal_key(&mut self, key: KeyEvent) -> LogAction {
 40→        // Ctrl+E: external editor describe (must be checked before 'e' match)
 41→        if key.modifiers.contains(KeyModifiers::CONTROL)
 42→            && matches!(key.code, KeyCode::Char('e') | KeyCode::Char('E'))
 43→        {
 44→            return if let Some(change) = self.selected_change() {
 45→                LogAction::DescribeExternal(change.change_id.clone())
 46→            } else {
 47→                LogAction::None
 48→            };
 49→        }
 50→
 51→        match key.code {
 52→            k if keys::is_move_down(k) => {
 53→                self.move_down();
 54→                LogAction::None
 55→            }
 56→            k if keys::is_move_up(k) => {
 57→                self.move_up();
 58→                LogAction::None
 59→            }
 60→            k if k == keys::GO_TOP => {
 61→                self.move_to_top();
 62→                LogAction::None
 63→            }
 64→            k if k == keys::GO_BOTTOM => {
 65→                self.move_to_bottom();
 66→                LogAction::None
 67→            }
 68→            k if k == keys::SEARCH_INPUT => {
 69→                self.start_search_input();
 70→                LogAction::None
 71→            }
 72→            k if k == keys::REVSET_INPUT => {
 73→                self.start_revset_input();
 74→                LogAction::None
 75→            }
 76→            k if k == keys::DESCRIBE => {
 77→                if let Some(change) = self.selected_change() {
 78→                    LogAction::StartDescribe(change.change_id.clone())
 79→                } else {
 80→                    LogAction::None
 81→                }
 82→            }
 83→            k if k == keys::EDIT => {
 84→                if let Some(change) = self.selected_change() {
 85→                    LogAction::Edit(change.change_id.clone())
 86→                } else {
 87→                    LogAction::None
 88→                }
 89→            }
 90→            k if k == keys::NEW_CHANGE => LogAction::NewChange,
 91→            k if k == keys::NEW_FROM => {
 92→                if let Some(change) = self.selected_change() {
 93→                    if change.is_working_copy {
 94→                        // @ で C を押した場合は c の使用を案内
 95→                        LogAction::NewChangeFromCurrent
 96→                    } else {
 97→                        // 表示名: 先頭 bookmark があれば優先、なければ short_id
 98→                        let display_name = change.bookmarks.first().cloned().unwrap_or_else(|| {
 99→                            change.change_id[..8.min(change.change_id.len())].to_string()
100→                        });
101→                        LogAction::NewChangeFrom {
102→                            change_id: change.change_id.clone(),
103→                            display_name,
104→                        }
105→                    }
106→                } else {
107→                    LogAction::None
108→                }
109→            }
110→            k if k == keys::SQUASH => {
111→                // Enter SquashSelect mode (validation happens in App layer)
112→                self.start_squash_select();
113→                LogAction::None
114→            }
115→            k if k == keys::ABANDON => {
116→                if let Some(change) = self.selected_change() {
117→                    // Let state.rs handle validation and show appropriate notification
118→                    LogAction::Abandon(change.change_id.clone())
119→                } else {
120→                    LogAction::None
121→                }
122→            }
123→            k if k == keys::SPLIT => {
124→                if let Some(change) = self.selected_change() {
125→                    // Let state.rs handle the interactive split
126→                    LogAction::Split(change.change_id.clone())
127→                } else {
128→                    LogAction::None
129→                }
130→            }
131→            k if k == keys::BOOKMARK => {
132→                self.start_bookmark_input();
133→                LogAction::None
134→            }
135→            k if k == keys::BOOKMARK_DELETE => {
136→                // Let state.rs handle the dialog
137→                LogAction::StartBookmarkDelete
138→            }
139→            k if k == keys::REBASE => {
140→                self.start_rebase_mode_select();
141→                LogAction::None
142→            }
143→            k if k == keys::ABSORB => LogAction::Absorb,
144→            k if k == keys::RESOLVE_LIST => {
145→                if let Some(change) = self.selected_change() {
146→                    LogAction::OpenResolveList {
147→                        change_id: change.change_id.clone(),
148→                        is_working_copy: change.is_working_copy,
149→                    }
150→                } else {
151→                    LogAction::None
152→                }
153→            }
154→            k if k == keys::SEARCH_NEXT => {
155→                self.search_next();
156→                LogAction::None
157→            }
158→            k if k == keys::SEARCH_PREV => {
159→                self.search_prev();
160→                LogAction::None
161→            }
162→            k if k == keys::OPEN_DIFF => {
163→                if let Some(change) = self.selected_change() {
164→                    LogAction::OpenDiff(change.change_id.clone())
165→                } else {
166→                    LogAction::None
167→                }
168→            }
169→            k if k == keys::FETCH => LogAction::Fetch,
170→            k if k == keys::PUSH => LogAction::StartPush,
171→            k if k == keys::TRACK => LogAction::StartTrack,
172→            k if k == keys::BOOKMARK_JUMP => LogAction::StartBookmarkJump,
173→            k if k == keys::COMPARE => {
174→                if self.start_compare_select() {
175→                    let from_id = self.compare_from.as_ref().unwrap().clone();
176→                    LogAction::StartCompare(from_id)
177→                } else {
178→                    LogAction::None
179→                }
180→            }
181→            k if k == keys::BOOKMARK_VIEW => LogAction::OpenBookmarkView,
182→            k if k == keys::NEXT_CHANGE => LogAction::NextChange,
183→            k if k == keys::PREV_CHANGE => LogAction::PrevChange,
184→            k if k == keys::LOG_REVERSE => LogAction::ToggleReversed,
185→            k if k == keys::DUPLICATE => {
186→                if let Some(change) = self.selected_change() {
187→                    LogAction::Duplicate(change.change_id.clone())
188→                } else {
189→                    LogAction::None
190→                }
191→            }
192→            k if k == keys::DIFFEDIT => {
193→                if let Some(change) = self.selected_change() {
194→                    LogAction::DiffEdit(change.change_id.clone())
195→                } else {
196→                    LogAction::None
197→                }
198→            }
199→            k if k == keys::EVOLOG => {
200→                if let Some(change) = self.selected_change() {
201→                    LogAction::OpenEvolog(change.change_id.clone())
202→                } else {
203→                    LogAction::None
204→                }
205→            }
206→            k if k == keys::REVERT => {
207→                if let Some(change) = self.selected_change() {
208→                    if change.is_empty {
209→                        // Empty commit has nothing to revert
210→                        LogAction::None
211→                    } else {
212→                        LogAction::Revert(change.change_id.clone())
213→                    }
214→                } else {
215→                    LogAction::None
216→                }
217→            }
218→            k if k == keys::SIMPLIFY_PARENTS => {
219→                if let Some(change) = self.selected_change() {
220→                    LogAction::SimplifyParents(change.change_id.clone())
221→                } else {
222→                    LogAction::None
223→                }
224→            }
225→            k if k == keys::PARALLELIZE => {
226→                if self.start_parallelize_select() {
227→                    let from_id = self.parallelize_from.as_ref().unwrap().clone();
228→                    LogAction::StartParallelize(from_id)
229→                } else {
230→                    LogAction::None
231→                }
232→            }
233→            _ => LogAction::None,
234→        }
235→    }
