237→    fn handle_search_input_key(&mut self, key: KeyEvent) -> LogAction {
238→        self.handle_text_input(key, |view, query| {
239→            if query.is_empty() {
240→                // Clear search query
241→                view.last_search_query = None;
242→            } else {
243→                view.last_search_query = Some(query);
244→                // Jump to first match from beginning
245→                view.search_first();
246→            }
247→            LogAction::None
248→        })
249→    }
250→
251→    fn handle_revset_input_key(&mut self, key: KeyEvent) -> LogAction {
252→        self.handle_text_input(key, |view, revset| {
253→            if revset.is_empty() {
254→                // Clear revset (reset to default)
255→                LogAction::ClearRevset
256→            } else {
257→                view.revset_history.push(revset.clone());
258→                LogAction::ExecuteRevset(revset)
259→            }
260→        })
261→    }
262→
263→    fn handle_describe_input_key(&mut self, key: KeyEvent) -> LogAction {
264→        self.handle_text_input(key, |view, message| {
265→            if let Some(change_id) = view.editing_change_id.take() {
266→                if message.trim().is_empty() {
267→                    LogAction::None // Empty = cancel
268→                } else {
269→                    LogAction::Describe { change_id, message }
270→                }
271→            } else {
272→                LogAction::None
273→            }
274→        })
275→    }
276→
277→    fn handle_bookmark_input_key(&mut self, key: KeyEvent) -> LogAction {
278→        self.handle_text_input(key, |view, name| {
279→            if let Some(change_id) = view.editing_change_id.take() {
280→                if name.is_empty() {
281→                    // Empty name = cancel
282→                    LogAction::None
283→                } else {
284→                    LogAction::CreateBookmark { change_id, name }
285→                }
286→            } else {
287→                LogAction::None
288→            }
289→        })
290→    }
291→
292→    /// Handle key events in rebase mode selection (r/s/A/B)
293→    ///
294→    /// Single key press selects the rebase mode, then transitions to RebaseSelect.
295→    fn handle_rebase_mode_select_key(&mut self, key: KeyEvent) -> LogAction {
296→        match key.code {
297→            KeyCode::Char('r') => {
298→                self.rebase_mode = RebaseMode::Revision;
299→                self.input_mode = InputMode::RebaseSelect;
300→                LogAction::None
301→            }
302→            KeyCode::Char('s') => {
303→                self.rebase_mode = RebaseMode::Source;
304→                self.input_mode = InputMode::RebaseSelect;
305→                LogAction::None
306→            }
307→            KeyCode::Char('b') => {
308→                self.rebase_mode = RebaseMode::Branch;
309→                self.input_mode = InputMode::RebaseSelect;
310→                LogAction::None
311→            }
312→            KeyCode::Char('A') => {
313→                self.rebase_mode = RebaseMode::InsertAfter;
314→                self.input_mode = InputMode::RebaseSelect;
315→                LogAction::None
316→            }
317→            KeyCode::Char('B') => {
318→                self.rebase_mode = RebaseMode::InsertBefore;
319→                self.input_mode = InputMode::RebaseSelect;
320→                LogAction::None
321→            }
322→            k if k == keys::ESC => {
323→                self.cancel_rebase_mode_select();
324→                LogAction::None
325→            }
326→            // Ignore other keys in mode selection
327→            _ => LogAction::None,
328→        }
329→    }
330→
331→    /// Handle key events in rebase destination selection mode
332→    ///
333→    /// In this mode, j/k navigates to select a destination, Enter confirms,
334→    /// and Esc cancels. Other keys are ignored to prevent accidental actions.
335→    fn handle_rebase_select_key(&mut self, key: KeyEvent) -> LogAction {
336→        match key.code {
337→            // Navigation
338→            k if keys::is_move_down(k) => {
339→                self.move_down();
340→                LogAction::None
341→            }
342→            k if keys::is_move_up(k) => {
343→                self.move_up();
344→                LogAction::None
345→            }
346→            k if k == keys::GO_TOP => {
347→                self.move_to_top();
348→                LogAction::None
349→            }
350→            k if k == keys::GO_BOTTOM => {
351→                self.move_to_bottom();
352→                LogAction::None
353→            }
354→            // Toggle --skip-emptied
355→            KeyCode::Char('S') => {
356→                self.skip_emptied = !self.skip_emptied;
357→                LogAction::None
358→            }
359→            // Confirm rebase
360→            KeyCode::Enter => {
361→                if let (Some(source), Some(dest_change)) =
362→                    (self.rebase_source.clone(), self.selected_change())
363→                {
364→                    let destination = dest_change.change_id.clone();
365→
366→                    // Prevent rebasing to self (all modes)
367→                    if source == destination {
368→                        return LogAction::None;
369→                    }
370→
371→                    let mode = self.rebase_mode;
372→                    let skip_emptied = self.skip_emptied;
373→                    self.rebase_source = None;
374→                    self.rebase_mode = RebaseMode::default();
375→                    self.skip_emptied = false;
376→                    self.input_mode = InputMode::Normal;
377→                    LogAction::Rebase {
378→                        source,
379→                        destination,
380→                        mode,
381→                        skip_emptied,
382→                    }
383→                } else {
384→                    LogAction::None
385→                }
386→            }
387→            // Cancel
388→            k if k == keys::ESC => {
389→                self.cancel_rebase_select();
390→                LogAction::None
391→            }
392→            // Ignore other keys in rebase select mode
393→            _ => LogAction::None,
394→        }
395→    }
396→
397→    /// Handle key events in squash destination selection mode
398→    ///
399→    /// In this mode, j/k navigates to select a destination, Enter confirms,
400→    /// and Esc cancels. Other keys are ignored to prevent accidental actions.
401→    fn handle_squash_select_key(&mut self, key: KeyEvent) -> LogAction {
402→        match key.code {
403→            // Navigation
404→            k if keys::is_move_down(k) => {
405→                self.move_down();
406→                LogAction::None
407→            }
408→            k if keys::is_move_up(k) => {
409→                self.move_up();
410→                LogAction::None
411→            }
412→            k if k == keys::GO_TOP => {
413→                self.move_to_top();
414→                LogAction::None
415→            }
416→            k if k == keys::GO_BOTTOM => {
417→                self.move_to_bottom();
418→                LogAction::None
419→            }
420→            // Confirm squash
421→            KeyCode::Enter => {
422→                if let (Some(source), Some(dest_change)) =
423→                    (self.squash_source.take(), self.selected_change())
424→                {
425→                    let destination = dest_change.change_id.clone();
426→
427→                    // Prevent squashing into self
428→                    if source == destination {
429→                        // Restore squash_source and stay in mode
430→                        self.squash_source = Some(source);
431→                        return LogAction::None;
432→                    }
433→
434→                    self.input_mode = InputMode::Normal;
435→                    LogAction::SquashInto {
436→                        source,
437→                        destination,
438→                    }
439→                } else {
440→                    LogAction::None
441→                }
442→            }
443→            // Cancel
444→            k if k == keys::ESC => {
445→                self.cancel_squash_select();
446→                LogAction::None
447→            }
448→            // Ignore other keys in squash select mode
449→            _ => LogAction::None,
450→        }
451→    }
452→
453→    /// Handle key events in compare revision selection mode
454→    ///
455→    /// In this mode, j/k navigates to select the "to" revision, Enter confirms,
456→    /// and Esc cancels. Selecting the same revision as "from" is guarded.
457→    fn handle_compare_select_key(&mut self, key: KeyEvent) -> LogAction {
458→        match key.code {
459→            // Navigation
460→            k if keys::is_move_down(k) => {
461→                self.move_down();
462→                LogAction::None
463→            }
464→            k if keys::is_move_up(k) => {
465→                self.move_up();
466→                LogAction::None
467→            }
468→            k if k == keys::GO_TOP => {
469→                self.move_to_top();
470→                LogAction::None
471→            }
472→            k if k == keys::GO_BOTTOM => {
473→                self.move_to_bottom();
474→                LogAction::None
475→            }
476→            // Confirm compare
477→            KeyCode::Enter => {
478→                if let (Some(from), Some(to_change)) =
479→                    (self.compare_from.take(), self.selected_change())
480→                {
481→                    let to = to_change.change_id.clone();
482→
483→                    // Prevent comparing a revision with itself
484→                    if from == to {
485→                        // Restore compare_from and stay in mode
486→                        self.compare_from = Some(from);
487→                        return LogAction::CompareSameRevision;
488→                    }
489→
490→                    self.input_mode = InputMode::Normal;
491→                    LogAction::Compare { from, to }
492→                } else {
493→                    LogAction::None
494→                }
495→            }
496→            // Cancel
497→            k if k == keys::ESC => {
498→                self.cancel_compare_select();
499→                LogAction::None
500→            }
501→            // Ignore other keys in compare select mode
502→            _ => LogAction::None,
503→        }
504→    }
505→
506→    /// Handle key events in parallelize selection mode
507→    ///
508→    /// In this mode, j/k navigates to select the end of the range, Enter confirms,
509→    /// and Esc cancels. Selecting the same revision as "from" is guarded.
510→    fn handle_parallelize_select_key(&mut self, key: KeyEvent) -> LogAction {
511→        match key.code {
512→            // Navigation
513→            k if keys::is_move_down(k) => {
514→                self.move_down();
515→                LogAction::None
516→            }
517→            k if keys::is_move_up(k) => {
518→                self.move_up();
519→                LogAction::None
520→            }
521→            k if k == keys::GO_TOP => {
522→                self.move_to_top();
523→                LogAction::None
524→            }
525→            k if k == keys::GO_BOTTOM => {
526→                self.move_to_bottom();
527→                LogAction::None
528→            }
529→            // Confirm parallelize
530→            KeyCode::Enter => {
531→                if let (Some(from), Some(to_change)) =
532→                    (self.parallelize_from.take(), self.selected_change())
533→                {
534→                    let to = to_change.change_id.clone();
535→
536→                    // Prevent parallelizing a single revision
537→                    if from == to {
538→                        // Restore parallelize_from and stay in mode
539→                        self.parallelize_from = Some(from);
540→                        return LogAction::ParallelizeSameRevision;
541→                    }
542→
543→                    self.input_mode = InputMode::Normal;
544→                    LogAction::Parallelize { from, to }
545→                } else {
546→                    LogAction::None
547→                }
548→            }
549→            // Cancel
550→            k if k == keys::ESC => {
551→                self.cancel_parallelize_select();
552→                LogAction::None
553→            }
554→            // Ignore other keys in parallelize select mode
555→            _ => LogAction::None,
556→        }
557→    }
558→
559→    fn handle_text_input<F>(&mut self, key: KeyEvent, on_submit: F) -> LogAction
560→    where
561→        F: FnOnce(&mut Self, String) -> LogAction,
562→    {
563→        match key.code {
564→            k if k == keys::ESC => {
565→                self.cancel_input();
566→                LogAction::None
567→            }
568→            k if k == keys::SUBMIT => {
569→                let input = std::mem::take(&mut self.input_buffer);
570→                self.input_mode = InputMode::Normal;
571→                on_submit(self, input)
572→            }
573→            KeyCode::Char(c)
574→                if !key
575→                    .modifiers
576→                    .intersects(KeyModifiers::CONTROL | KeyModifiers::ALT) =>
577→            {
578→                self.input_buffer.push(c);
579→                LogAction::None
580→            }
581→            KeyCode::Backspace => {
582→                self.input_buffer.pop();
583→                LogAction::None
584→            }
585→            _ => LogAction::None,
586→        }
587→    }
588→
589→    // ─────────────────────────────────────────────────────────────────────────
590→    // Search
591→    // ─────────────────────────────────────────────────────────────────────────
592→
593→    /// Check if a change matches the search query
594→    pub(crate) fn change_matches(&self, change: &Change, query_lower: &str) -> bool {
595→        change.change_id.to_lowercase().contains(query_lower)
596→            || change.description.to_lowercase().contains(query_lower)
597→            || change.author.to_lowercase().contains(query_lower)
598→            || change
599→                .bookmarks
600→                .iter()
601→                .any(|b| b.to_lowercase().contains(query_lower))
602→    }
603→
604→    /// Search for first match from beginning (used when search is confirmed)
605→    pub fn search_first(&mut self) -> bool {
606→        self.search(SearchKind::First)
607→    }
608→
609→    /// Search for next match (n key)
610→    pub fn search_next(&mut self) -> bool {
611→        self.search(SearchKind::Next)
612→    }
613→
614→    /// Search for previous match (N key)
615→    pub fn search_prev(&mut self) -> bool {
616→        self.search(SearchKind::Prev)
617→    }
618→
619→    fn search(&mut self, kind: SearchKind) -> bool {
620→        let Some(ref query) = self.last_search_query else {
621→            return false;
622→        };
623→        if self.changes.is_empty() {
624→            return false;
625→        }
626→
627→        let query_lower = query.to_lowercase();
628→
629→        let found = match kind {
630→            SearchKind::First => self.find_match_in(0..self.changes.len(), &query_lower),
631→            SearchKind::Next => {
632→                let start = self.selected_index + 1;
633→                let forward = start..self.changes.len();
634→                let wrap = 0..self.selected_index;
635→                self.find_match_in(forward, &query_lower)
636→                    .or_else(|| self.find_match_in(wrap, &query_lower))
637→            }
638→            SearchKind::Prev => {
639→                let backward = (0..self.selected_index).rev();
640→                let wrap = (self.selected_index + 1..self.changes.len()).rev();
641→                self.find_match_in(backward, &query_lower)
642→                    .or_else(|| self.find_match_in(wrap, &query_lower))
643→            }
644→        };
645→
646→        if let Some(index) = found {
647→            self.selected_index = index;
648→            // Also update selection_cursor so card mode stays in sync
649→            if let Some(cursor) = self.selectable_indices.iter().position(|&i| i == index) {
650→                self.selection_cursor = cursor;
651→            }
652→            return true;
653→        }
654→
655→        false
656→    }
657→
658→    fn find_match_in<I>(&self, indices: I, query_lower: &str) -> Option<usize>
659→    where
660→        I: IntoIterator<Item = usize>,
661→    {
662→        indices
663→            .into_iter()
664→            .find(|&i| self.change_matches(&self.changes[i], query_lower))
665→    }
666→}
