269→        let is_parallelize_from = self.input_mode == InputMode::ParallelizeSelect
270→            && self.parallelize_from.as_ref() == Some(&change.change_id);
271→
272→        // Apply styling
273→        if is_rebase_source || is_squash_source || is_compare_from || is_parallelize_from {
274→            // Highlight rebase/squash source with distinct background
275→            line = line.style(
276→                Style::default()
277→                    .bg(Color::DarkGray)
278→                    .fg(Color::Yellow)
279→                    .add_modifier(Modifier::BOLD),
280→            );
281→        } else if is_selected {
282→            line = line.style(
283→                Style::default()
284→                    .fg(theme::selection::FG)
285→                    .bg(theme::selection::BG)
286→                    .add_modifier(Modifier::BOLD),
287→            );
288→        }
289→
290→        line
291→    }
