293→    fn render_input_bar(&self, frame: &mut Frame, area: Rect) {
294→        let Some((prompt, title)) = self.input_mode.input_bar_meta() else {
295→            return;
296→        };
297→
298→        let input_text = format!("{}{}", prompt, self.input_buffer);
299→
300→        // Calculate available width (area width minus borders)
301→        let available_width = area.width.saturating_sub(2) as usize;
302→
303→        // Early return if no space for input
304→        if available_width == 0 {
305→            return;
306→        }
307→
308→        // Truncate display text if too long (show end of input, UTF-8 safe)
309→        let char_count = input_text.chars().count();
310→        let display_text = if char_count > available_width {
311→            let skip = char_count.saturating_sub(available_width.saturating_sub(1)); // -1 for ellipsis
312→            format!("…{}", input_text.chars().skip(skip).collect::<String>())
313→        } else {
314→            input_text.clone()
315→        };
316→
317→        let paragraph =
318→            Paragraph::new(display_text).block(components::bordered_block(Line::from(title)));
319→
320→        frame.render_widget(paragraph, area);
321→
322→        // Show cursor (clamped to available width, character-based)
323→        let cursor_pos = char_count.min(available_width);
324→        frame.set_cursor_position((area.x + cursor_pos as u16 + 1, area.y + 1));
325→    }
326→}
