        let hints = current_hints(View::Log, InputMode::Normal, &ctx);
        assert!(hints.iter().any(|h| h.key == "P"), "Push hint missing");
        assert!(hints.iter().any(|h| h.key == "D"), "Del Bkm hint missing");
