  1→//! Input handling for the application
  2→
  3→use crossterm::event::{KeyCode, KeyEvent, KeyModifiers};
  4→
  5→use super::state::{App, View};
  6→use crate::keys;
  7→use crate::ui::views::{
  8→    BlameAction, BookmarkAction, DiffAction, EvologAction, InputMode, LogAction, OperationAction,
  9→    RenameState, ResolveAction, StatusAction, StatusInputMode,
 10→};
 11→
 12→impl App {
 13→    /// Handle key events
 14→    pub fn on_key_event(&mut self, key: KeyEvent) {
 15→        // Handle active dialog first (blocks other input)
 16→        if let Some(ref mut dialog) = self.active_dialog {
 17→            if let Some(result) = dialog.handle_key(key) {
 18→                // handle_dialog_result() clears active_dialog internally.
 19→                // Do NOT clear again here — dialog chains (e.g. remote select → push confirm)
 20→                // set a new active_dialog inside handle_dialog_result().
 21→                self.handle_dialog_result(result);
 22→            }
 23→            return;
 24→        }
 25→
 26→        // Clear error message and expired notification on any key press
 27→        self.error_message = None;
 28→        self.clear_expired_notification();
 29→
 30→        // Handle Ctrl+C globally
 31→        if key.modifiers.contains(KeyModifiers::CONTROL)
 32→            && matches!(key.code, KeyCode::Char('c') | KeyCode::Char('C'))
 33→        {
 34→            self.quit();
 35→            return;
 36→        }
 37→
 38→        // Handle Ctrl+R for redo (only in Log view, normal mode)
 39→        // Only active in Normal mode to avoid conflicts with input modes
 40→        if key.modifiers.contains(KeyModifiers::CONTROL)
 41→            && matches!(key.code, KeyCode::Char('r') | KeyCode::Char('R'))
 42→            && self.current_view == View::Log
 43→            && matches!(self.log_view.input_mode, InputMode::Normal)
 44→        {
 45→            self.notification = None; // Clear any existing notification
 46→            self.execute_redo();
 47→            return;
 48→        }
 49→
 50→        // Handle Ctrl+L for refresh (all views, normal mode)
 51→        if keys::is_refresh_key(&key) {
 52→            // Skip if in input mode or special mode (like RebaseSelect)
 53→            let in_special_mode = match self.current_view {
 54→                View::Log => !matches!(self.log_view.input_mode, InputMode::Normal),
 55→                View::Status => self.status_view.input_mode != StatusInputMode::Normal,
 56→                View::Help => self.help_search_input,
 57→                _ => false,
 58→            };
 59→            if !in_special_mode {
 60→                self.execute_refresh();
 61→                return;
 62→            }
 63→        }
 64→
 65→        // If in input mode or rebase select mode, delegate all keys to the view (skip global handling)
 66→        if self.current_view == View::Log && !matches!(self.log_view.input_mode, InputMode::Normal)
 67→        {
 68→            let action = self.log_view.handle_key(key);
 69→            self.handle_log_action(action);
 70→            return;
 71→        }
 72→
 73→        // Handle Status View input mode
 74→        if self.current_view == View::Status
 75→            && self.status_view.input_mode != StatusInputMode::Normal
 76→        {
 77→            let action = self.status_view.handle_key(key);
 78→            self.handle_status_action(action);
 79→            return;
 80→        }
 81→
 82→        // Handle Help search input mode (skip global keys so Esc/q/Tab stay in search)
 83→        if self.current_view == View::Help && self.help_search_input {
 84→            self.handle_view_key(key);
 85→            return;
 86→        }
 87→
 88→        if self.handle_global_key(key) {
 89→            return;
 90→        }
 91→
 92→        self.handle_view_key(key);
 93→    }
 94→
 95→    fn handle_global_key(&mut self, key: KeyEvent) -> bool {
 96→        match key.code {
 97→            keys::QUIT => {
 98→                self.handle_quit();
 99→                true
100→            }
101→            keys::ESC => {
102→                // Don't intercept Esc when bookmark rename is active
103→                if self.current_view == View::Bookmark && self.bookmark_view.rename_state.is_some()
104→                {
105→                    return false;
106→                }
107→                self.handle_back();
108→                true
109→            }
110→            keys::HELP => {
111→                self.go_to_view(View::Help);
112→                true
113→            }
114→            keys::TAB => {
115→                self.next_view();
116→                true
117→            }
118→            keys::STATUS_VIEW if self.current_view == View::Log => {
119→                self.go_to_view(View::Status);
120→                true
121→            }
122→            keys::UNDO if matches!(self.current_view, View::Log | View::Bookmark) => {
123→                self.notification = None; // Clear any existing notification
124→                self.execute_undo();
125→                true
126→            }
127→            keys::OPERATION_HISTORY if self.current_view == View::Log => {
128→                self.open_operation_history();
129→                true
130→            }
131→            _ => false,
132→        }
133→    }
134→
135→    fn handle_quit(&mut self) {
136→        if self.current_view == View::Log {
137→            self.quit();
138→        } else {
139→            self.go_back();
140→        }
141→    }
142→
143→    fn handle_back(&mut self) {
144→        if self.current_view != View::Log {
145→            self.go_back();
146→        }
147→    }
148→
149→    fn handle_view_key(&mut self, key: KeyEvent) {
150→        match self.current_view {
151→            View::Log => {
152→                // Preview toggle (handled at App level since it's App state)
153→                if key.code == keys::PREVIEW
154→                    && matches!(self.log_view.input_mode, InputMode::Normal)
155→                {
156→                    self.preview_enabled = !self.preview_enabled;
157→                    if self.preview_enabled {
158→                        // Immediate fetch on toggle-ON (no 200ms wait)
159→                        self.update_preview_if_needed();
160→                        self.resolve_pending_preview();
161→                    } else {
162→                        // Clear pending fetch on disable (keep cache for toggle back ON)
163→                        self.preview_pending_id = None;
164→                    }
165→                    return;
166→                }
167→
168→                let action = self.log_view.handle_key(key);
169→                self.handle_log_action(action);
170→
171→                // Update preview after key processing (debounced)
172→                // Guard: only if still on Log view (Enter → Diff would have transitioned away)
173→                if self.preview_enabled && self.current_view == View::Log {
174→                    self.update_preview_if_needed();
175→                }
176→            }
177→            View::Diff => {
178→                if let Some(ref mut diff_view) = self.diff_view {
179→                    let visible_height = self.last_frame_height.get() as usize;
180→                    let action = diff_view.handle_key_with_height(key, visible_height);
181→                    self.handle_diff_action(action);
182→                }
183→            }
184→            View::Status => {
185→                let visible_height = self.last_frame_height.get() as usize;
186→                let action = self.status_view.handle_key_with_height(key, visible_height);
187→                self.handle_status_action(action);
188→            }
189→            View::Operation => {
190→                let action = self.operation_view.handle_key(key);
191→                self.handle_operation_action(action);
192→            }
193→            View::Blame => {
194→                if let Some(ref mut blame_view) = self.blame_view {
195→                    let action = blame_view.handle_key(key);
196→                    self.handle_blame_action(action);
197→                }
198→            }
199→            View::Bookmark => {
200→                let action = self.bookmark_view.handle_key(key);
201→                self.handle_bookmark_action(action);
202→            }
203→            View::Resolve => {
204→                if let Some(ref mut resolve_view) = self.resolve_view {
205→                    let action = resolve_view.handle_key(key);
206→                    self.handle_resolve_action(action);
207→                }
208→            }
209→            View::Evolog => {
210→                if let Some(ref mut evolog_view) = self.evolog_view {
211→                    let action = evolog_view.handle_key(key);
212→                    self.handle_evolog_action(action);
213→                }
214→            }
215→            View::Help => {
216→                if self.help_search_input {
217→                    // Search input mode: capture text
218→                    match key.code {
219→                        KeyCode::Esc => {
220→                            self.help_search_input = false;
221→                            self.help_input_buffer.clear();
222→                        }
223→                        KeyCode::Enter => {
224→                            let query = std::mem::take(&mut self.help_input_buffer);
225→                            self.help_search_input = false;
226→                            if query.is_empty() {
227→                                self.help_search_query = None;
228→                            } else {
229→                                self.help_search_query = Some(query.clone());
230→                                // Jump to first match
231→                                let indices = crate::ui::widgets::matching_line_indices(&query);
232→                                if let Some(&first) = indices.first() {
233→                                    self.help_scroll = first;
234→                                }
235→                            }
236→                        }
237→                        KeyCode::Char(c)
238→                            if !key
239→                                .modifiers
240→                                .intersects(KeyModifiers::CONTROL | KeyModifiers::ALT) =>
241→                        {
242→                            self.help_input_buffer.push(c);
243→                        }
244→                        KeyCode::Backspace => {
245→                            self.help_input_buffer.pop();
246→                        }
247→                        _ => {}
248→                    }
249→                } else {
250→                    // Normal mode: scrolling + search start + n/N navigation
251→                    if keys::is_move_down(key.code) {
252→                        self.help_scroll = self.help_scroll.saturating_add(1);
253→                    } else if keys::is_move_up(key.code) {
254→                        self.help_scroll = self.help_scroll.saturating_sub(1);
255→                    } else if key.code == keys::GO_BOTTOM {
256→                        self.help_scroll = u16::MAX; // clamped during render
257→                    } else if key.code == keys::GO_TOP {
258→                        self.help_scroll = 0;
259→                    } else if key.code == keys::SEARCH_INPUT {
260→                        self.help_search_input = true;
261→                        self.help_input_buffer.clear();
262→                    } else if key.code == keys::SEARCH_NEXT {
263→                        if let Some(ref query) = self.help_search_query {
264→                            let indices = crate::ui::widgets::matching_line_indices(query);
265→                            if let Some(next) = indices.iter().find(|&&i| i > self.help_scroll) {
266→                                self.help_scroll = *next;
267→                            } else if let Some(&first) = indices.first() {
268→                                // Wrap to top
269→                                self.help_scroll = first;
270→                            }
271→                        }
272→                    } else if key.code == keys::SEARCH_PREV
273→                        && let Some(ref query) = self.help_search_query
274→                    {
275→                        let indices = crate::ui::widgets::matching_line_indices(query);
276→                        if let Some(prev) = indices.iter().rev().find(|&&i| i < self.help_scroll) {
277→                            self.help_scroll = *prev;
278→                        } else if let Some(&last) = indices.last() {
279→                            // Wrap to bottom
280→                            self.help_scroll = last;
281→                        }
282→                    }
283→                }
284→            }
285→        }
286→    }
287→
288→    fn handle_log_action(&mut self, action: LogAction) {
289→        match action {
290→            LogAction::None => {}
291→
292→            // Navigation
293→            LogAction::OpenDiff(_)
294→            | LogAction::ExecuteRevset(_)
295→            | LogAction::ClearRevset
296→            | LogAction::OpenBookmarkView
297→            | LogAction::OpenEvolog(_)
298→            | LogAction::OpenResolveList { .. } => {
299→                self.handle_log_navigation(action);
300→            }
301→
302→            // Editing
303→            LogAction::StartDescribe(_)
304→            | LogAction::Describe { .. }
305→            | LogAction::DescribeExternal(_)
306→            | LogAction::Edit(_)
307→            | LogAction::NewChange
308→            | LogAction::NewChangeFrom { .. }
309→            | LogAction::NewChangeFromCurrent
310→            | LogAction::SquashInto { .. }
311→            | LogAction::Abandon(_)
312→            | LogAction::Split(_)
313→            | LogAction::Duplicate(_)
314→            | LogAction::DiffEdit(_)
315→            | LogAction::Revert(_)
316→            | LogAction::SimplifyParents(_) => {
317→                self.handle_log_editing(action);
318→            }
319→
320→            // Bookmark
321→            LogAction::CreateBookmark { .. }
322→            | LogAction::StartBookmarkDelete
323→            | LogAction::StartBookmarkJump => {
324→                self.handle_log_bookmark(action);
325→            }
326→
327→            // Git
328→            LogAction::Fetch | LogAction::StartPush | LogAction::StartTrack => {
329→                self.handle_log_git(action);
330→            }
331→
332→            // Rebase / Parallelize
333→            LogAction::Rebase { .. }
334→            | LogAction::Absorb
335→            | LogAction::StartParallelize(_)
336→            | LogAction::Parallelize { .. }
337→            | LogAction::ParallelizeSameRevision => {
338→                self.handle_log_rebase(action);
339→            }
340→
341→            // Compare
342→            LogAction::StartCompare(_)
343→            | LogAction::Compare { .. }
344→            | LogAction::CompareSameRevision => {
345→                self.handle_log_compare(action);
346→            }
347→
348→            // Misc
349→            LogAction::NextChange | LogAction::PrevChange | LogAction::ToggleReversed => {
350→                self.handle_log_misc(action);
351→            }
352→        }
353→    }
354→
355→    fn handle_log_navigation(&mut self, action: LogAction) {
356→        match action {
357→            LogAction::OpenDiff(change_id) => self.open_diff(&change_id),
358→            LogAction::ExecuteRevset(revset) => self.refresh_log(Some(&revset)),
359→            LogAction::ClearRevset => self.refresh_log(None),
360→            LogAction::OpenBookmarkView => self.open_bookmark_view(),
361→            LogAction::OpenEvolog(change_id) => self.open_evolog(&change_id),
362→            LogAction::OpenResolveList {
363→                change_id,
364→                is_working_copy,
365→            } => self.open_resolve_view(&change_id, is_working_copy),
366→            _ => {}
367→        }
368→    }
369→
370→    fn handle_log_editing(&mut self, action: LogAction) {
371→        use crate::ui::components::{Dialog, DialogCallback};
372→
373→        match action {
374→            LogAction::StartDescribe(change_id) => self.start_describe_input(&change_id),
375→            LogAction::Describe { change_id, message } => {
376→                self.execute_describe(&change_id, &message);
377→            }
378→            LogAction::DescribeExternal(change_id) => self.execute_describe_external(&change_id),
379→            LogAction::Edit(change_id) => self.execute_edit(&change_id),
380→            LogAction::NewChange => self.execute_new_change(),
381→            LogAction::NewChangeFrom {
382→                change_id,
383→                display_name,
384→            } => self.execute_new_change_from(&change_id, &display_name),
385→            LogAction::NewChangeFromCurrent => {
386→                self.notify_info("Use 'c' to create from current change");
387→            }
388→            LogAction::SquashInto {
389→                source,
390→                destination,
391→            } => self.execute_squash_into(&source, &destination),
392→            LogAction::Abandon(change_id) => self.execute_abandon(&change_id),
393→            LogAction::Split(change_id) => self.execute_split(&change_id),
394→            LogAction::Duplicate(change_id) => self.duplicate(&change_id),
395→            LogAction::DiffEdit(change_id) => self.execute_diffedit(&change_id, None),
396→            LogAction::Revert(change_id) => {
397→                let short_id = &change_id[..8.min(change_id.len())];
398→                self.active_dialog = Some(Dialog::confirm(
399→                    "Revert Change",
400→                    format!("Revert changes from {}?", short_id),
401→                    Some(
402→                        "Creates a new commit that undoes these changes. Undo with 'u' if needed."
403→                            .to_string(),
404→                    ),
405→                    DialogCallback::Revert { change_id },
406→                ));
407→            }
408→            LogAction::SimplifyParents(change_id) => {
409→                let short_id = &change_id[..8.min(change_id.len())];
410→                self.active_dialog = Some(Dialog::confirm(
411→                    "Simplify Parents",
412→                    format!("Simplify parents for {}?", short_id),
413→                    None,
414→                    DialogCallback::SimplifyParents { change_id },
415→                ));
416→            }
417→            _ => {}
418→        }
419→    }
420→
421→    fn handle_log_bookmark(&mut self, action: LogAction) {
422→        match action {
423→            LogAction::CreateBookmark { change_id, name } => {
424→                self.execute_bookmark_create(&change_id, &name);
425→            }
426→            LogAction::StartBookmarkDelete => self.start_bookmark_delete(),
427→            LogAction::StartBookmarkJump => self.start_bookmark_jump(),
428→            _ => {}
429→        }
430→    }
431→
432→    fn handle_log_git(&mut self, action: LogAction) {
433→        match action {
434→            LogAction::Fetch => self.start_fetch(),
435→            LogAction::StartPush => self.start_push(),
436→            LogAction::StartTrack => self.start_track(),
437→            _ => {}
438→        }
439→    }
440→
441→    fn handle_log_rebase(&mut self, action: LogAction) {
442→        use crate::ui::components::{Dialog, DialogCallback};
443→
444→        match action {
445→            LogAction::Rebase {
446→                source,
447→                destination,
448→                mode,
449→                skip_emptied,
450→            } => self.execute_rebase(&source, &destination, mode, skip_emptied),
451→            LogAction::Absorb => self.execute_absorb(),
452→            LogAction::StartParallelize(from_id) => {
453→                self.notify_info(format!("From: {}. Select end and press Enter", from_id));
454→            }
455→            LogAction::Parallelize { from, to } => {
456→                let from_short = &from[..8.min(from.len())];
457→                let to_short = &to[..8.min(to.len())];
458→                self.active_dialog = Some(Dialog::confirm(
459→                    "Parallelize",
460→                    format!("Parallelize {}::{}?", from_short, to_short),
461→                    None,
462→                    DialogCallback::Parallelize { from, to },
463→                ));
464→            }
465→            LogAction::ParallelizeSameRevision => {
466→                self.notify_info("Cannot parallelize single revision");
467→            }
468→            _ => {}
469→        }
470→    }
471→
472→    fn handle_log_compare(&mut self, action: LogAction) {
473→        match action {
474→            LogAction::StartCompare(from_id) => {
475→                self.notify_info(format!("From: {}. Select 'To' and press Enter", from_id));
476→            }
477→            LogAction::Compare { ref from, ref to } => {
478→                let msg = format!("Comparing {} -> {}", from, to);
479→                self.open_compare_diff(from, to);
480→                if self.error_message.is_none() {
481→                    self.notify_info(&msg);
482→                }
483→            }
484→            LogAction::CompareSameRevision => {
485→                self.notify_info("Cannot compare revision with itself");
486→            }
487→            _ => {}
488→        }
489→    }
490→
491→    fn handle_log_misc(&mut self, action: LogAction) {
492→        match action {
493→            LogAction::NextChange => self.execute_next(),
494→            LogAction::PrevChange => self.execute_prev(),
495→            LogAction::ToggleReversed => {
496→                let selected_id = self.log_view.selected_change().map(|c| c.change_id.clone());
497→                self.log_view.reversed = !self.log_view.reversed;
498→                let revset = self.log_view.current_revset.clone();
499→                self.refresh_log(revset.as_deref());
500→                if let Some(ref id) = selected_id
501→                    && !self.log_view.select_change_by_id(id)
502→                {
503→                    self.log_view.select_working_copy();
504→                }
505→                let label = if self.log_view.reversed {
506→                    "oldest first"
507→                } else {
508→                    "newest first"
509→                };
510→                self.notify_info(format!("Log order: {}", label));
511→            }
512→            _ => {}
513→        }
514→    }
515→
516→    fn handle_bookmark_action(&mut self, action: BookmarkAction) {
517→        match action {
518→            BookmarkAction::None => {}
519→            BookmarkAction::Jump(change_id) => {
520→                self.execute_bookmark_jump(&change_id);
521→                self.go_to_view(View::Log);
522→            }
523→            BookmarkAction::Track(full_name) => {
524→                self.execute_track(&[full_name]);
525→            }
526→            BookmarkAction::Untrack(full_name) => {
527→                self.execute_untrack(&full_name);
528→            }
529→            BookmarkAction::Delete(name) => {
530→                self.execute_bookmark_delete(&[name]);
531→            }
532→            BookmarkAction::StartRename(old_name) => {
533→                self.bookmark_view.rename_state = Some(RenameState::new(old_name));
534→            }
535→            BookmarkAction::ConfirmRename { old_name, new_name } => {
536→                self.execute_bookmark_rename(&old_name, &new_name);
537→            }
538→            BookmarkAction::CancelRename => {
539→                // rename_state already cleared by BookmarkView
540→            }
541→            BookmarkAction::Forget(name) => {
542→                use crate::ui::components::{Dialog, DialogCallback};
543→                self.active_dialog = Some(Dialog::confirm(
544→                    "Forget Bookmark",
545→                    format!(
546→                        "Forget bookmark '{}'?\n\n\
547→                         This removes remote tracking.\n\
548→                         Use 'D' for local delete only.\n\
549→                         Undo with 'u' if needed.",
550→                        name
551→                    ),
552→                    None,
553→                    DialogCallback::BookmarkForget,
554→                ));
555→                self.pending_forget_bookmark = Some(name);
556→            }
557→            BookmarkAction::Move(name) => {
558→                self.start_bookmark_move(&name);
559→            }
560→            BookmarkAction::MoveUnavailable => {
561→                self.notify_info("Move is available only for local bookmarks");
562→            }
563→        }
564→    }
565→
566→    fn handle_diff_action(&mut self, action: DiffAction) {
567→        match action {
568→            DiffAction::None => {}
569→            DiffAction::Back => {
570→                self.go_back();
571→            }
572→            DiffAction::OpenBlame { file_path } => {
573→                // Get the current change_id from diff_view for proper revision
574→                let revision = self.diff_view.as_ref().map(|v| v.change_id.clone());
575→                self.open_blame(&file_path, revision.as_deref());
576→            }
577→            DiffAction::ShowNotification(message) => {
578→                self.notify_info(&message);
579→            }
580→            DiffAction::CopyToClipboard { full } => {
581→                self.copy_diff_to_clipboard(full);
582→            }
583→            DiffAction::ExportToFile => {
584→                self.export_diff_to_file();
585→            }
586→            DiffAction::CycleFormat => {
587→                self.cycle_diff_format();
588→            }
589→        }
590→    }
591→
592→    fn handle_status_action(&mut self, action: StatusAction) {
593→        match action {
594→            StatusAction::None => {}
595→            StatusAction::ShowFileDiff {
596→                change_id,
597→                file_path,
598→            } => {
599→                self.open_diff_at_file(&change_id, &file_path);
600→            }
601→            StatusAction::OpenBlame { file_path } => {
602→                self.open_blame(&file_path, None);
603→            }
604→            StatusAction::Commit { message } => {
605→                self.execute_commit(&message);
606→            }
607→            StatusAction::JumpToConflict => {
608→                // Selection already moved by StatusView; no further action needed
609→            }
610→            StatusAction::RestoreFile { file_path } => {
611→                // Show confirm dialog before restoring
612→                use crate::ui::components::{Dialog, DialogCallback};
613→                self.active_dialog = Some(Dialog::confirm(
614→                    "Restore File",
615→                    format!(
616→                        "Restore '{}'?\nThis discards your changes to this file.",
617→                        file_path
618→                    ),
619→                    Some("Undo with 'u' if needed.".to_string()),
620→                    DialogCallback::RestoreFile {
621→                        file_path: file_path.clone(),
622→                    },
623→                ));
624→            }
625→            StatusAction::RestoreAll => {
626→                use crate::ui::components::{Dialog, DialogCallback};
627→                self.active_dialog = Some(Dialog::confirm(
628→                    "Restore All Files",
629→                    "Restore all files?\nThis discards ALL your changes in the working copy.",
630→                    Some("Undo with 'u' if needed.".to_string()),
631→                    DialogCallback::RestoreAll,
632→                ));
633→            }
634→            StatusAction::DiffEdit { file_path } => {
635→                self.execute_diffedit("@", Some(&file_path));
636→            }
637→        }
638→    }
639→
640→    fn handle_operation_action(&mut self, action: OperationAction) {
641→        match action {
642→            OperationAction::None => {}
643→            OperationAction::Back => {
644→                self.go_back();
645→            }
646→            OperationAction::Restore(operation_id) => {
647→                self.execute_op_restore(&operation_id);
648→            }
649→        }
650→    }
651→
652→    fn handle_resolve_action(&mut self, action: ResolveAction) {
653→        match action {
654→            ResolveAction::None => {}
655→            ResolveAction::Back => {
656→                self.resolve_view = None;
657→                // Mark log dirty so conflict indicators update on return
658→                self.dirty.log = true;
659→                self.dirty.op_log = true;
660→                self.go_back();
661→            }
662→            ResolveAction::ResolveExternal(file_path) => {
663→                self.execute_resolve_external(&file_path);
664→            }
665→            ResolveAction::ResolveOurs(file_path) => {
666→                self.execute_resolve_ours(&file_path);
667→            }
668→            ResolveAction::ResolveTheirs(file_path) => {
669→                self.execute_resolve_theirs(&file_path);
670→            }
671→            ResolveAction::ShowDiff(file_path) => {
672→                // Open diff for the change, jumping to the file
673→                let change_id = self
674→                    .resolve_view
675→                    .as_ref()
676→                    .map(|v| v.change_id.clone())
677→                    .unwrap_or_default();
678→                self.open_diff_at_file(&change_id, &file_path);
679→            }
680→        }
681→    }
682→
683→    fn handle_evolog_action(&mut self, action: EvologAction) {
684→        match action {
685→            EvologAction::None => {}
686→            EvologAction::Back => {
687→                self.go_back();
688→            }
689→            EvologAction::OpenDiff(change_id) => {
690→                self.open_diff(&change_id);
691→            }
692→        }
693→    }
694→
695→    fn handle_blame_action(&mut self, action: BlameAction) {
696→        match action {
697→            BlameAction::None => {}
698→            BlameAction::Back => {
699→                self.go_back();
700→            }
701→            BlameAction::OpenDiff(change_id) => {
702→                self.open_diff(&change_id);
703→            }
704→            BlameAction::JumpToLog(change_id) => {
705→                self.jump_to_log(&change_id);
706→            }
707→        }
708→    }
709→}
