 31→            View::Diff => self.render_diff_view(frame, notification.as_ref()),
 32→            View::Status => self.render_status_view(frame, notification.as_ref()),
 33→            View::Operation => self.render_operation_view(frame, notification.as_ref()),
 34→            View::Blame => self.render_blame_view(frame, notification.as_ref()),
 35→            View::Resolve => self.render_resolve_view(frame, notification.as_ref()),
 36→            View::Bookmark => self.render_bookmark_view(frame, notification.as_ref()),
 37→            View::Evolog => self.render_evolog_view(frame, notification.as_ref()),
 38→            View::Help => self.render_help_view(frame),
 39→        }
