 41→        // Render error banner above status bar (errors are always shown prominently)
 42→        if let Some(ref error) = self.error_message {
 43→            let status_bar_height = self.get_current_status_bar_height(frame.area().width);
 44→            render_error_banner(frame, error, status_bar_height);
