 53→    /// Get the status bar height for the current view
 54→    fn get_current_status_bar_height(&self, width: u16) -> u16 {
 55→        match self.current_view {
 56→            View::Log | View::Status | View::Operation => {
 57→                let ctx = self.build_hint_context();
 58→                let hints = keys::current_hints(self.current_view, self.log_view.input_mode, &ctx);
