 60→            }
 61→            View::Bookmark => {
 62→                let ctx = self.build_bookmark_hint_context();
 63→                let hints = keys::current_hints(View::Bookmark, self.log_view.input_mode, &ctx);
 64→                status_hints_height(&hints, width)
 65→            }
 66→            View::Resolve => {
 67→                let ctx = self.build_resolve_hint_context();
 68→                let hints = keys::current_hints(View::Resolve, self.log_view.input_mode, &ctx);
 69→                status_hints_height(&hints, width)
 70→            }
 71→            View::Evolog | View::Diff => 1,
 72→            View::Blame => status_hints_height(keys::BLAME_VIEW_HINTS, width),
 73→            View::Help => 0,
 74→        }
 75→    }
 76→
 77→    /// Build HintContext from current App state (Log/Status/Operation views)
 78→    fn build_hint_context(&self) -> HintContext {
 79→        let change = self.log_view.selected_change();
 80→        HintContext {
 81→            has_bookmarks: change.is_some_and(|c| !c.bookmarks.is_empty()),
 82→            has_conflicts: change.is_some_and(|c| c.has_conflict),
