//! Input handling and search for LogView

use crossterm::event::{KeyCode, KeyEvent, KeyModifiers};

use crate::keys;
use crate::model::Change;

use super::{InputMode, LogAction, LogView, RebaseMode};

/// Search direction/mode
#[derive(Clone, Copy)]
enum SearchKind {
    First,
    Next,
    Prev,
}

impl LogView {
    // ─────────────────────────────────────────────────────────────────────────
    // Input handling
    // ─────────────────────────────────────────────────────────────────────────

    /// Handle key event and return action
    pub fn handle_key(&mut self, key: KeyEvent) -> LogAction {
        match self.input_mode {
            InputMode::Normal => self.handle_normal_key(key),
            InputMode::SearchInput => self.handle_search_input_key(key),
            InputMode::RevsetInput => self.handle_revset_input_key(key),
            InputMode::DescribeInput => self.handle_describe_input_key(key),
            InputMode::BookmarkInput => self.handle_bookmark_input_key(key),
            InputMode::RebaseModeSelect => self.handle_rebase_mode_select_key(key),
            InputMode::RebaseSelect => self.handle_rebase_select_key(key),
            InputMode::SquashSelect => self.handle_squash_select_key(key),
            InputMode::CompareSelect => self.handle_compare_select_key(key),
            InputMode::ParallelizeSelect => self.handle_parallelize_select_key(key),
            InputMode::RebaseRevsetInput => self.handle_rebase_revset_input_key(key),
        }
    }

    fn handle_normal_key(&mut self, key: KeyEvent) -> LogAction {
        // Ctrl+E: external editor describe (must be checked before 'e' match)
        if key.modifiers.contains(KeyModifiers::CONTROL)
            && matches!(key.code, KeyCode::Char('e') | KeyCode::Char('E'))
        {
            return if let Some(change) = self.selected_change() {
                LogAction::DescribeExternal(change.change_id.clone())
            } else {
                LogAction::None
            };
        }

        match key.code {
            k if keys::is_move_down(k) => {
                self.move_down();
                LogAction::None
            }
            k if keys::is_move_up(k) => {
                self.move_up();
                LogAction::None
            }
            k if k == keys::GO_TOP => {
                self.move_to_top();
                LogAction::None
            }
            k if k == keys::GO_BOTTOM => {
                self.move_to_bottom();
                LogAction::None
            }
            k if k == keys::SEARCH_INPUT => {
                self.start_search_input();
                LogAction::None
            }
            k if k == keys::REVSET_INPUT => {
                self.start_revset_input();
                LogAction::None
            }
            k if k == keys::DESCRIBE => {
                if let Some(change) = self.selected_change() {
                    LogAction::StartDescribe(change.change_id.clone())
                } else {
                    LogAction::None
                }
            }
            k if k == keys::EDIT => {
                if let Some(change) = self.selected_change() {
                    LogAction::Edit(change.change_id.clone())
                } else {
                    LogAction::None
                }
            }
            k if k == keys::NEW_CHANGE => LogAction::NewChange,
            k if k == keys::NEW_FROM => {
                if let Some(change) = self.selected_change() {
                    if change.is_working_copy {
                        // @ で C を押した場合は c の使用を案内
                        LogAction::NewChangeFromCurrent
                    } else {
                        // 表示名: 先頭 bookmark があれば優先、なければ short_id
                        let display_name = change.bookmarks.first().cloned().unwrap_or_else(|| {
                            change.change_id[..8.min(change.change_id.len())].to_string()
                        });
                        LogAction::NewChangeFrom {
                            change_id: change.change_id.clone(),
                            display_name,
                        }
                    }
                } else {
                    LogAction::None
                }
            }
            k if k == keys::SQUASH => {
                // Enter SquashSelect mode (validation happens in App layer)
                self.start_squash_select();
                LogAction::None
            }
            k if k == keys::ABANDON => {
                if let Some(change) = self.selected_change() {
                    // Let state.rs handle validation and show appropriate notification
                    LogAction::Abandon(change.change_id.clone())
                } else {
                    LogAction::None
                }
            }
            k if k == keys::SPLIT => {
                if let Some(change) = self.selected_change() {
                    // Let state.rs handle the interactive split
                    LogAction::Split(change.change_id.clone())
                } else {
                    LogAction::None
                }
            }
            k if k == keys::BOOKMARK => {
                self.start_bookmark_input();
                LogAction::None
            }
            k if k == keys::BOOKMARK_DELETE => {
                // Let state.rs handle the dialog
                LogAction::StartBookmarkDelete
            }
            k if k == keys::REBASE => {
                self.start_rebase_mode_select();
                LogAction::None
            }
            k if k == keys::ABSORB => LogAction::Absorb,
            k if k == keys::RESOLVE_LIST => {
                if let Some(change) = self.selected_change() {
                    LogAction::OpenResolveList {
                        change_id: change.change_id.clone(),
                        is_working_copy: change.is_working_copy,
                    }
                } else {
                    LogAction::None
                }
            }
            k if k == keys::SEARCH_NEXT => {
                self.search_next();
                LogAction::None
            }
            k if k == keys::SEARCH_PREV => {
                self.search_prev();
                LogAction::None
            }
            k if k == keys::OPEN_DIFF => {
                if let Some(change) = self.selected_change() {
                    LogAction::OpenDiff(change.change_id.clone())
                } else {
                    LogAction::None
                }
            }
            k if k == keys::FETCH => LogAction::Fetch,
            k if k == keys::PUSH => LogAction::StartPush,
            k if k == keys::TRACK => LogAction::StartTrack,
            k if k == keys::BOOKMARK_JUMP => LogAction::StartBookmarkJump,
            k if k == keys::COMPARE => {
                if self.start_compare_select() {
                    let from_id = self.compare_from.as_ref().unwrap().clone();
                    LogAction::StartCompare(from_id)
                } else {
                    LogAction::None
                }
            }
            k if k == keys::BOOKMARK_VIEW => LogAction::OpenBookmarkView,
            k if k == keys::NEXT_CHANGE => LogAction::NextChange,
            k if k == keys::PREV_CHANGE => LogAction::PrevChange,
            k if k == keys::LOG_REVERSE => LogAction::ToggleReversed,
            k if k == keys::DUPLICATE => {
                if let Some(change) = self.selected_change() {
                    LogAction::Duplicate(change.change_id.clone())
                } else {
                    LogAction::None
                }
            }
            k if k == keys::DIFFEDIT => {
                if let Some(change) = self.selected_change() {
                    LogAction::DiffEdit(change.change_id.clone())
                } else {
                    LogAction::None
                }
            }
            k if k == keys::EVOLOG => {
                if let Some(change) = self.selected_change() {
                    LogAction::OpenEvolog(change.change_id.clone())
                } else {
                    LogAction::None
                }
            }
            k if k == keys::REVERT => {
                if let Some(change) = self.selected_change() {
                    if change.is_empty {
                        // Empty commit has nothing to revert
                        LogAction::None
                    } else {
                        LogAction::Revert(change.change_id.clone())
                    }
                } else {
                    LogAction::None
                }
            }
            k if k == keys::SIMPLIFY_PARENTS => {
                if let Some(change) = self.selected_change() {
                    LogAction::SimplifyParents(change.change_id.clone())
                } else {
                    LogAction::None
                }
            }
            k if k == keys::PARALLELIZE => {
                if self.start_parallelize_select() {
                    let from_id = self.parallelize_from.as_ref().unwrap().clone();
                    LogAction::StartParallelize(from_id)
                } else {
                    LogAction::None
                }
            }
            _ => LogAction::None,
        }
    }

    fn handle_search_input_key(&mut self, key: KeyEvent) -> LogAction {
        self.handle_text_input(key, |view, query| {
            if query.is_empty() {
                // Clear search query
                view.last_search_query = None;
            } else {
                view.last_search_query = Some(query);
                // Jump to first match from beginning
                view.search_first();
            }
            LogAction::None
        })
    }

    fn handle_revset_input_key(&mut self, key: KeyEvent) -> LogAction {
        self.handle_text_input(key, |view, revset| {
            if revset.is_empty() {
                // Clear revset (reset to default)
                LogAction::ClearRevset
            } else {
                view.revset_history.push(revset.clone());
                LogAction::ExecuteRevset(revset)
            }
        })
    }

    fn handle_describe_input_key(&mut self, key: KeyEvent) -> LogAction {
        self.handle_text_input(key, |view, message| {
            if let Some(change_id) = view.editing_change_id.take() {
                if message.trim().is_empty() {
                    LogAction::None // Empty = cancel
                } else {
                    LogAction::Describe { change_id, message }
                }
            } else {
                LogAction::None
            }
        })
    }

    fn handle_bookmark_input_key(&mut self, key: KeyEvent) -> LogAction {
        self.handle_text_input(key, |view, name| {
            if let Some(change_id) = view.editing_change_id.take() {
                if name.is_empty() {
                    // Empty name = cancel
                    LogAction::None
                } else {
                    LogAction::CreateBookmark { change_id, name }
                }
            } else {
                LogAction::None
            }
        })
    }

    /// Handle key events in rebase mode selection (r/s/A/B)
    ///
    /// Single key press selects the rebase mode, then transitions to RebaseSelect.
    fn handle_rebase_mode_select_key(&mut self, key: KeyEvent) -> LogAction {
        match key.code {
            KeyCode::Char('r') => {
                self.rebase_mode = RebaseMode::Revision;
                self.input_mode = InputMode::RebaseSelect;
                LogAction::None
            }
            KeyCode::Char('s') => {
                self.rebase_mode = RebaseMode::Source;
                self.input_mode = InputMode::RebaseSelect;
                LogAction::None
            }
            KeyCode::Char('b') => {
                self.rebase_mode = RebaseMode::Branch;
                self.input_mode = InputMode::RebaseSelect;
                LogAction::None
            }
            KeyCode::Char('A') => {
                self.rebase_mode = RebaseMode::InsertAfter;
                self.input_mode = InputMode::RebaseSelect;
                LogAction::None
            }
            KeyCode::Char('B') => {
                self.rebase_mode = RebaseMode::InsertBefore;
                self.input_mode = InputMode::RebaseSelect;
                LogAction::None
            }
            k if k == keys::ESC => {
                self.cancel_rebase_mode_select();
                LogAction::None
            }
            // Ignore other keys in mode selection
            _ => LogAction::None,
        }
    }

    /// Handle key events in rebase destination selection mode
    ///
    /// In this mode, j/k navigates to select a destination, Enter confirms,
    /// and Esc cancels. Other keys are ignored to prevent accidental actions.
    fn handle_rebase_select_key(&mut self, key: KeyEvent) -> LogAction {
        match key.code {
            // Navigation
            k if keys::is_move_down(k) => {
                self.move_down();
                LogAction::None
            }
            k if keys::is_move_up(k) => {
                self.move_up();
                LogAction::None
            }
            k if k == keys::GO_TOP => {
                self.move_to_top();
                LogAction::None
            }
            k if k == keys::GO_BOTTOM => {
                self.move_to_bottom();
                LogAction::None
            }
            // Enter revset input (only for Revision/Source/Branch modes)
            KeyCode::Char(':') => {
                if matches!(
                    self.rebase_mode,
                    RebaseMode::Revision | RebaseMode::Source | RebaseMode::Branch
                ) {
                    self.input_buffer.clear();
                    self.input_mode = InputMode::RebaseRevsetInput;
                }
                LogAction::None
            }
            // Toggle --skip-emptied
            KeyCode::Char('S') => {
                self.skip_emptied = !self.skip_emptied;
                LogAction::None
            }
            // Confirm rebase
            KeyCode::Enter => {
                if let (Some(source), Some(dest_change)) =
                    (self.rebase_source.clone(), self.selected_change())
                {
                    let destination = dest_change.change_id.clone();

                    // Prevent rebasing to self (skip for revset — let jj validate)
                    if !self.rebase_use_revset && source == destination {
                        return LogAction::None;
                    }

                    let mode = self.rebase_mode;
                    let skip_emptied = self.skip_emptied;
                    let use_revset = self.rebase_use_revset;
                    self.rebase_source = None;
                    self.rebase_mode = RebaseMode::default();
                    self.skip_emptied = false;
                    self.rebase_use_revset = false;
                    self.input_mode = InputMode::Normal;
                    LogAction::Rebase {
                        source,
                        destination,
                        mode,
                        skip_emptied,
                        use_revset,
                    }
                } else {
                    LogAction::None
                }
            }
            // Cancel
            k if k == keys::ESC => {
                self.cancel_rebase_select();
                LogAction::None
            }
            // Ignore other keys in rebase select mode
            _ => LogAction::None,
        }
    }

    /// Handle key events in squash destination selection mode
    ///
    /// In this mode, j/k navigates to select a destination, Enter confirms,
    /// and Esc cancels. Other keys are ignored to prevent accidental actions.
    fn handle_squash_select_key(&mut self, key: KeyEvent) -> LogAction {
        match key.code {
            // Navigation
            k if keys::is_move_down(k) => {
                self.move_down();
                LogAction::None
            }
            k if keys::is_move_up(k) => {
                self.move_up();
                LogAction::None
            }
            k if k == keys::GO_TOP => {
                self.move_to_top();
                LogAction::None
            }
            k if k == keys::GO_BOTTOM => {
                self.move_to_bottom();
                LogAction::None
            }
            // Confirm squash
            KeyCode::Enter => {
                if let (Some(source), Some(dest_change)) =
                    (self.squash_source.take(), self.selected_change())
                {
                    let destination = dest_change.change_id.clone();

                    // Prevent squashing into self
                    if source == destination {
                        // Restore squash_source and stay in mode
                        self.squash_source = Some(source);
                        return LogAction::None;
                    }

                    self.input_mode = InputMode::Normal;
                    LogAction::SquashInto {
                        source,
                        destination,
                    }
                } else {
                    LogAction::None
                }
            }
            // Cancel
            k if k == keys::ESC => {
                self.cancel_squash_select();
                LogAction::None
            }
            // Ignore other keys in squash select mode
            _ => LogAction::None,
        }
    }

    /// Handle key events in compare revision selection mode
    ///
    /// In this mode, j/k navigates to select the "to" revision, Enter confirms,
    /// and Esc cancels. Selecting the same revision as "from" is guarded.
    fn handle_compare_select_key(&mut self, key: KeyEvent) -> LogAction {
        match key.code {
            // Navigation
            k if keys::is_move_down(k) => {
                self.move_down();
                LogAction::None
            }
            k if keys::is_move_up(k) => {
                self.move_up();
                LogAction::None
            }
            k if k == keys::GO_TOP => {
                self.move_to_top();
                LogAction::None
            }
            k if k == keys::GO_BOTTOM => {
                self.move_to_bottom();
                LogAction::None
            }
            // Confirm compare
            KeyCode::Enter => {
                if let (Some(from), Some(to_change)) =
                    (self.compare_from.take(), self.selected_change())
                {
                    let to = to_change.change_id.clone();

                    // Prevent comparing a revision with itself
                    if from == to {
                        // Restore compare_from and stay in mode
                        self.compare_from = Some(from);
                        return LogAction::CompareSameRevision;
                    }

                    self.input_mode = InputMode::Normal;
                    LogAction::Compare { from, to }
                } else {
                    LogAction::None
                }
            }
            // Cancel
            k if k == keys::ESC => {
                self.cancel_compare_select();
                LogAction::None
            }
            // Ignore other keys in compare select mode
            _ => LogAction::None,
        }
    }

    /// Handle key events in parallelize selection mode
    ///
    /// In this mode, j/k navigates to select the end of the range, Enter confirms,
    /// and Esc cancels. Selecting the same revision as "from" is guarded.
    fn handle_parallelize_select_key(&mut self, key: KeyEvent) -> LogAction {
        match key.code {
            // Navigation
            k if keys::is_move_down(k) => {
                self.move_down();
                LogAction::None
            }
            k if keys::is_move_up(k) => {
                self.move_up();
                LogAction::None
            }
            k if k == keys::GO_TOP => {
                self.move_to_top();
                LogAction::None
            }
            k if k == keys::GO_BOTTOM => {
                self.move_to_bottom();
                LogAction::None
            }
            // Confirm parallelize
            KeyCode::Enter => {
                if let (Some(from), Some(to_change)) =
                    (self.parallelize_from.take(), self.selected_change())
                {
                    let to = to_change.change_id.clone();

                    // Prevent parallelizing a single revision
                    if from == to {
                        // Restore parallelize_from and stay in mode
                        self.parallelize_from = Some(from);
                        return LogAction::ParallelizeSameRevision;
                    }

                    self.input_mode = InputMode::Normal;
                    LogAction::Parallelize { from, to }
                } else {
                    LogAction::None
                }
            }
            // Cancel
            k if k == keys::ESC => {
                self.cancel_parallelize_select();
                LogAction::None
            }
            // Ignore other keys in parallelize select mode
            _ => LogAction::None,
        }
    }

    fn handle_text_input<F>(&mut self, key: KeyEvent, on_submit: F) -> LogAction
    where
        F: FnOnce(&mut Self, String) -> LogAction,
    {
        match key.code {
            k if k == keys::ESC => {
                self.cancel_input();
                LogAction::None
            }
            k if k == keys::SUBMIT => {
                let input = std::mem::take(&mut self.input_buffer);
                self.input_mode = InputMode::Normal;
                on_submit(self, input)
            }
            KeyCode::Char(c)
                if !key
                    .modifiers
                    .intersects(KeyModifiers::CONTROL | KeyModifiers::ALT) =>
            {
                self.input_buffer.push(c);
                LogAction::None
            }
            KeyCode::Backspace => {
                self.input_buffer.pop();
                LogAction::None
            }
            _ => LogAction::None,
        }
    }

    // ─────────────────────────────────────────────────────────────────────────
    // Search
    // ─────────────────────────────────────────────────────────────────────────

    /// Check if a change matches the search query
    pub(crate) fn change_matches(&self, change: &Change, query_lower: &str) -> bool {
        change.change_id.to_lowercase().contains(query_lower)
            || change.description.to_lowercase().contains(query_lower)
            || change.author.to_lowercase().contains(query_lower)
            || change
                .bookmarks
                .iter()
                .any(|b| b.to_lowercase().contains(query_lower))
    }

    /// Search for first match from beginning (used when search is confirmed)
    pub fn search_first(&mut self) -> bool {
        self.search(SearchKind::First)
    }

    /// Search for next match (n key)
    pub fn search_next(&mut self) -> bool {
        self.search(SearchKind::Next)
    }

    /// Search for previous match (N key)
    pub fn search_prev(&mut self) -> bool {
        self.search(SearchKind::Prev)
    }

    fn search(&mut self, kind: SearchKind) -> bool {
        let Some(ref query) = self.last_search_query else {
            return false;
        };
        if self.changes.is_empty() {
            return false;
        }

        let query_lower = query.to_lowercase();

        let found = match kind {
            SearchKind::First => self.find_match_in(0..self.changes.len(), &query_lower),
            SearchKind::Next => {
                let start = self.selected_index + 1;
                let forward = start..self.changes.len();
                let wrap = 0..self.selected_index;
                self.find_match_in(forward, &query_lower)
                    .or_else(|| self.find_match_in(wrap, &query_lower))
            }
            SearchKind::Prev => {
                let backward = (0..self.selected_index).rev();
                let wrap = (self.selected_index + 1..self.changes.len()).rev();
                self.find_match_in(backward, &query_lower)
                    .or_else(|| self.find_match_in(wrap, &query_lower))
            }
        };

        if let Some(index) = found {
            self.selected_index = index;
            // Also update selection_cursor so card mode stays in sync
            if let Some(cursor) = self.selectable_indices.iter().position(|&i| i == index) {
                self.selection_cursor = cursor;
            }
            return true;
        }

        false
    }

    fn find_match_in<I>(&self, indices: I, query_lower: &str) -> Option<usize>
    where
        I: IntoIterator<Item = usize>,
    {
        indices
            .into_iter()
            .find(|&i| self.change_matches(&self.changes[i], query_lower))
    }
}

//! Rendering for LogView

use ratatui::{
    Frame,
    layout::{Constraint, Layout, Rect},
    style::{Color, Modifier, Style, Stylize},
    text::{Line, Span},
    widgets::Paragraph,
};

use crate::jj::constants;
use crate::model::{Change, Notification};
use crate::ui::{components, symbols, theme};

use super::{InputMode, LogView, RebaseMode, empty_text};

impl LogView {
    /// Render the view with optional notification in title bar
    pub fn render(&mut self, frame: &mut Frame, area: Rect, notification: Option<&Notification>) {
        // Split area for input bar if in input modes
        let (log_area, input_area) = match self.input_mode {
            InputMode::Normal
            | InputMode::RebaseModeSelect
            | InputMode::RebaseSelect
            | InputMode::SquashSelect
            | InputMode::CompareSelect
            | InputMode::ParallelizeSelect => (area, None),
            InputMode::SearchInput
            | InputMode::RevsetInput
            | InputMode::DescribeInput
            | InputMode::BookmarkInput => {
                let chunks =
                    Layout::vertical([Constraint::Min(1), Constraint::Length(3)]).split(area);
                (chunks[0], Some(chunks[1]))
            }
        };

        self.render_log_list(frame, log_area, notification);

        // Render input bar if in input mode
        if let Some(input_area) = input_area {
            self.render_input_bar(frame, input_area);
        }
    }

    fn render_log_list(&self, frame: &mut Frame, area: Rect, notification: Option<&Notification>) {
        let title = self.build_title();

        // Build notification line for title bar (with truncation if needed)
        let title_width = title.width();
        let available_for_notif = area.width.saturating_sub(title_width as u16 + 4) as usize; // +4 for borders/padding
        let notif_line = notification
            .filter(|n| !n.is_expired())
            .map(|n| components::build_notification_title(n, Some(available_for_notif)))
            .filter(|line| !line.spans.is_empty());

        let block = components::bordered_block_with_notification(title, notif_line);

        if self.changes.is_empty() {
            self.render_empty_state(frame, area, block);
            return;
        }

        let inner_height = area.height.saturating_sub(2) as usize; // borders
        if inner_height == 0 {
            return;
        }

        // Calculate scroll offset to keep selection visible
        let scroll_offset = self.calculate_scroll_offset(inner_height);

        // Build lines - each change is one line (graph prefix from jj)
        let mut lines: Vec<Line> = Vec::new();
        for (idx, change) in self.changes.iter().enumerate().skip(scroll_offset) {
            if lines.len() >= inner_height {
                break;
            }

            let is_selected = idx == self.selected_index && !change.is_graph_only;
            let line = self.build_change_line(change, is_selected);
            lines.push(line);
        }

        let paragraph = Paragraph::new(lines).block(block);

        frame.render_widget(paragraph, area);
    }

    fn build_title(&self) -> Line<'static> {
        // Special title for RebaseModeSelect mode
        if self.input_mode == InputMode::RebaseModeSelect {
            return Line::from(" Tij - Log View [Rebase: Select mode (r/s/b/A/B)] ")
                .bold()
                .yellow()
                .centered();
        }

        // Special title for RebaseSelect mode (varies by rebase_mode)
        if self.input_mode == InputMode::RebaseSelect {
            let title = match self.rebase_mode {
                RebaseMode::Revision => " Tij - Log View [Rebase: Select destination] ".to_string(),
                RebaseMode::Source => {
                    " Tij - Log View [Rebase -s: Select destination (with descendants)] "
                        .to_string()
                }
                RebaseMode::Branch => {
                    " Tij - Log View [Rebase -b: Select destination (branch)] ".to_string()
                }
                RebaseMode::InsertAfter => {
                    " Tij - Log View [Rebase: Select insert-after target] ".to_string()
                }
                RebaseMode::InsertBefore => {
                    " Tij - Log View [Rebase: Select insert-before target] ".to_string()
                }
            };
            return Line::from(title).bold().yellow().centered();
        }

        // Special title for SquashSelect mode
        if self.input_mode == InputMode::SquashSelect {
            return Line::from(" Tij - Log View [Squash: Select destination] ")
                .bold()
                .yellow()
                .centered();
        }

        // Special title for CompareSelect mode
        if self.input_mode == InputMode::CompareSelect {
            let from_id = self.compare_from.as_deref().unwrap_or("?");
            return Line::from(format!(
                " Tij - Log View [Compare: From={}, Select To] ",
                from_id
            ))
            .bold()
            .yellow()
            .centered();
        }

        // Special title for ParallelizeSelect mode
        if self.input_mode == InputMode::ParallelizeSelect {
            let from_id = self.parallelize_from.as_deref().unwrap_or("?");
            return Line::from(format!(
                " Tij - Log View [Parallelize: From={}, Select end] ",
                from_id
            ))
            .bold()
            .yellow()
            .centered();
        }

        let title_text = match (&self.current_revset, &self.last_search_query) {
            (Some(revset), Some(query)) => {
                format!(" Tij - Log View [{}] [Search: {}] ", revset, query)
            }
            (Some(revset), None) => {
                format!(" Tij - Log View [{}] ", revset)
            }
            (None, Some(query)) => {
                format!(" Tij - Log View [Search: {}] ", query)
            }
            (None, None) => " Tij - Log View ".to_string(),
        };
        Line::from(title_text).bold().cyan().centered()
    }

    fn render_empty_state(
        &self,
        frame: &mut Frame,
        area: Rect,
        block: ratatui::widgets::Block<'static>,
    ) {
        let paragraph =
            components::empty_state(empty_text::TITLE, Some(empty_text::HINT)).block(block);

        frame.render_widget(paragraph, area);
    }

    fn calculate_scroll_offset(&self, visible_changes: usize) -> usize {
        if visible_changes == 0 {
            return 0;
        }

        let mut offset = self.scroll_offset;

        // Ensure selected item is visible
        if self.selected_index < offset {
            offset = self.selected_index;
        } else if self.selected_index >= offset + visible_changes {
            offset = self.selected_index - visible_changes + 1;
        }

        offset
    }

    fn build_change_line(&self, change: &Change, is_selected: bool) -> Line<'static> {
        let mut spans = Vec::new();

        // Graph prefix (from jj output)
        if !change.graph_prefix.is_empty() {
            spans.push(Span::styled(
                change.graph_prefix.clone(),
                Style::default().fg(theme::log_view::GRAPH_LINE),
            ));
        }

        // For graph-only lines, just return the prefix
        if change.is_graph_only {
            return Line::from(spans);
        }

        // Change ID
        spans.push(Span::styled(
            format!("{} ", change.short_id()),
            Style::default().fg(theme::log_view::CHANGE_ID),
        ));

        // Author (if not root)
        if change.change_id != constants::ROOT_CHANGE_ID {
            spans.push(Span::raw(format!("{} ", change.author)));
            spans.push(Span::styled(
                format!("{} ", change.timestamp),
                Style::default().fg(theme::log_view::TIMESTAMP),
            ));
        }

        // Bookmarks
        if !change.bookmarks.is_empty() {
            spans.push(Span::styled(
                format!("{} ", change.bookmarks.join(", ")),
                Style::default().fg(theme::log_view::BOOKMARK),
            ));
        }

        // Conflict indicator
        if change.has_conflict {
            spans.push(Span::styled(
                "[CONFLICT] ",
                Style::default().fg(Color::Red).add_modifier(Modifier::BOLD),
            ));
        }

        // Description
        let description = change.display_description();
        if change.is_empty && description == symbols::empty::NO_DESCRIPTION {
            spans.push(Span::styled(
                format!("{} ", symbols::empty::CHANGE_LABEL),
                Style::default().fg(theme::log_view::EMPTY_LABEL),
            ));
        }
        spans.push(Span::raw(description.to_string()));

        let mut line = Line::from(spans);

        // Check if this is the rebase source (in RebaseModeSelect or RebaseSelect mode)
        let is_rebase_source = matches!(
            self.input_mode,
            InputMode::RebaseModeSelect | InputMode::RebaseSelect
        ) && self.rebase_source.as_ref() == Some(&change.change_id);

        // Check if this is the squash source (in SquashSelect mode)
        let is_squash_source = self.input_mode == InputMode::SquashSelect
            && self.squash_source.as_ref() == Some(&change.change_id);

        // Check if this is the compare "from" (in CompareSelect mode)
        let is_compare_from = self.input_mode == InputMode::CompareSelect
            && self.compare_from.as_ref() == Some(&change.change_id);

        // Check if this is the parallelize "from" (in ParallelizeSelect mode)
        let is_parallelize_from = self.input_mode == InputMode::ParallelizeSelect
            && self.parallelize_from.as_ref() == Some(&change.change_id);

        // Apply styling
        if is_rebase_source || is_squash_source || is_compare_from || is_parallelize_from {
            // Highlight rebase/squash source with distinct background
            line = line.style(
                Style::default()
                    .bg(Color::DarkGray)
                    .fg(Color::Yellow)
                    .add_modifier(Modifier::BOLD),
            );
        } else if is_selected {
            line = line.style(
                Style::default()
                    .fg(theme::selection::FG)
                    .bg(theme::selection::BG)
                    .add_modifier(Modifier::BOLD),
            );
        }

        line
    }

    fn render_input_bar(&self, frame: &mut Frame, area: Rect) {
        let Some((prompt, title)) = self.input_mode.input_bar_meta() else {
            return;
        };

        let input_text = format!("{}{}", prompt, self.input_buffer);

        // Calculate available width (area width minus borders)
        let available_width = area.width.saturating_sub(2) as usize;

        // Early return if no space for input
        if available_width == 0 {
            return;
        }

        // Truncate display text if too long (show end of input, UTF-8 safe)
        let char_count = input_text.chars().count();
        let display_text = if char_count > available_width {
            let skip = char_count.saturating_sub(available_width.saturating_sub(1)); // -1 for ellipsis
            format!("…{}", input_text.chars().skip(skip).collect::<String>())
        } else {
            input_text.clone()
        };

        let paragraph =
            Paragraph::new(display_text).block(components::bordered_block(Line::from(title)));

        frame.render_widget(paragraph, area);

        // Show cursor (clamped to available width, character-based)
        let cursor_pos = char_count.min(available_width);
        frame.set_cursor_position((area.x + cursor_pos as u16 + 1, area.y + 1));
    }
}

