    let skip_color = if skip_emptied {
        Color::Green
    } else {
        Color::DarkGray
    };
    vec![
        KeyHint {
            key: "j/k",
            label: "Navigate",
            color: Color::Blue,
        },
        KeyHint {
            key: "S",
            label: skip_label,
            color: skip_color,
        },
        KeyHint {
            key: "Enter",
            label: "Rebase",
            color: Color::Green,
        },
        KeyHint {
            key: "Esc",
