/// Build RebaseSelect mode status bar hints (dynamic for skip-emptied state and rebase mode)
fn rebase_select_hints(
    skip_emptied: bool,
    rebase_mode: crate::model::RebaseMode,
) -> Vec<KeyHint> {
    use crate::model::RebaseMode;

    let skip_label = if skip_emptied {
        "Skip-empty:ON"
    } else {
        "Skip-empty:OFF"
    };
    let skip_color = if skip_emptied {
        Color::Green
    } else {
        Color::DarkGray
    };
    let mut hints = vec![
        KeyHint {
            key: "j/k",
            label: "Navigate",
            color: Color::Blue,
        },
        KeyHint {
            key: "S",
            label: skip_label,
            color: skip_color,
        },
    ];
    // Show revset hint only for modes that support it
    if matches!(
        rebase_mode,
        RebaseMode::Revision | RebaseMode::Source | RebaseMode::Branch
    ) {
        hints.push(KeyHint {
            key: ":",
            label: "Revset",
            color: Color::Magenta,
        });
    }
    hints.push(KeyHint {
        key: "Enter",
        label: "Rebase",
        color: Color::Green,
    });
    hints.push(KeyHint {
        key: "Esc",
        label: "Cancel",
        color: Color::Red,
    });
    hints
}

