   1→//! jj operations (actions that modify repository state)
   2→
   3→mod bookmark;
   4→mod dialog;
   5→mod push;
   6→
   7→use crate::model::{CompareInfo, DiffContent, DiffDisplayFormat, Notification, RebaseMode};
   8→use crate::ui::components::{Dialog, DialogCallback, SelectItem};
   9→
  10→use super::state::{App, DirtyFlags, View};
  11→
  12→/// Suspend TUI mode (raw mode off, leave alternate screen).
  13→///
  14→/// Returns a scope guard that restores TUI mode on drop.
  15→/// Use this before running interactive jj commands (describe --edit, split, diffedit, resolve).
  16→fn suspend_tui() -> impl Drop {
  17→    use crossterm::execute;
  18→    use crossterm::terminal::{
  19→        Clear, ClearType, EnterAlternateScreen, LeaveAlternateScreen, disable_raw_mode,
  20→        enable_raw_mode,
  21→    };
  22→    use std::io::stdout;
  23→
  24→    let _ = disable_raw_mode();
  25→    let _ = execute!(stdout(), LeaveAlternateScreen, Clear(ClearType::All));
  26→
  27→    scopeguard::guard((), |_| {
  28→        let _ = enable_raw_mode();
  29→        let _ = execute!(stdout(), EnterAlternateScreen);
  30→    })
  31→}
  32→
  33→impl App {
  34→    // ── Notification / error helpers ──────────────────────────────────
  35→
  36→    /// Set a success notification (green)
  37→    pub(crate) fn notify_success(&mut self, msg: impl Into<String>) {
  38→        self.notification = Some(Notification::success(msg));
  39→    }
  40→
  41→    /// Set an info notification (blue)
  42→    pub(crate) fn notify_info(&mut self, msg: impl Into<String>) {
  43→        self.notification = Some(Notification::info(msg));
  44→    }
  45→
  46→    /// Set a warning notification (yellow)
  47→    pub(crate) fn notify_warning(&mut self, msg: impl Into<String>) {
  48→        self.notification = Some(Notification::warning(msg));
  49→    }
  50→
  51→    /// Set an error message (displayed in error area)
  52→    pub(crate) fn set_error(&mut self, msg: impl Into<String>) {
  53→        self.error_message = Some(msg.into());
  54→    }
  55→
  56→    /// Handle a simple jj action result: notify on success, set error on failure
  57→    ///
  58→    /// For the common pattern: Ok → notify_success + mark_dirty, Err → set_error.
  59→    /// `err_prefix` is prepended to the error: `"{err_prefix}: {e}"`.
  60→    /// Not suitable for actions that parse output, branch on result, or have side-effects.
  61→    fn run_jj_action(
  62→        &mut self,
  63→        result: Result<String, crate::jj::JjError>,
  64→        err_prefix: &str,
  65→        success_msg: &str,
  66→        dirty: DirtyFlags,
  67→    ) {
  68→        match result {
  69→            Ok(_) => {
  70→                self.notify_success(success_msg);
  71→                self.mark_dirty_and_refresh_current(dirty);
  72→            }
  73→            Err(e) => {
  74→                self.set_error(format!("{}: {}", err_prefix, e));
  75→            }
  76→        }
  77→    }
  78→
  79→    /// Execute undo operation
  80→    pub(crate) fn execute_undo(&mut self) {
  81→        let result = self.jj.undo();
  82→        self.run_jj_action(result, "Undo failed", "Undo complete", DirtyFlags::all());
  83→    }
  84→
  85→    /// Start describe input mode by fetching the full description
  86→    ///
  87→    /// If the description is multi-line, automatically opens the external
  88→    /// editor instead of the 1-line input bar to prevent data loss.
  89→    pub(crate) fn start_describe_input(&mut self, change_id: &str) {
  90→        // Fetch the full (multi-line) description from jj
  91→        match self.jj.get_description(change_id) {
  92→            Ok(full_description) => {
  93→                let description = full_description.trim_end_matches('\n').to_string();
  94→
  95→                // Multi-line: fall through to external editor directly
  96→                if description.lines().nth(1).is_some() {
  97→                    self.execute_describe_external(change_id);
  98→                    return;
  99→                }
 100→
 101→                self.log_view
 102→                    .set_describe_input(change_id.to_string(), description);
 103→            }
 104→            Err(e) => {
 105→                self.set_error(format!("Failed to get description: {}", e));
 106→            }
 107→        }
 108→    }
 109→
 110→    /// Execute describe via external editor (jj describe --edit)
 111→    ///
 112→    /// Temporarily exits TUI mode to allow the editor to run.
 113→    /// Uses before/after description comparison to detect changes,
 114→    /// since jj describe --edit exits 0 regardless of whether the user saved.
 115→    pub(crate) fn execute_describe_external(&mut self, change_id: &str) {
 116→        // Pre-check: immutable commits cannot be described
 117→        if self.jj.is_immutable(change_id) {
 118→            self.set_error("Cannot describe: commit is immutable");
 119→            return;
 120→        }
 121→
 122→        // Capture description before editing for change detection
 123→        let before = match self.jj.get_description(change_id) {
 124→            Ok(desc) => Some(desc.trim_end().to_string()),
 125→            Err(_) => None,
 126→        };
 127→
 128→        let _guard = suspend_tui();
 129→
 130→        // Run jj describe --editor (blocking, interactive)
 131→        let result = self.jj.describe_edit_interactive(change_id);
 132→
 133→        match result {
 134→            Ok(status) if status.success() => {
 135→                // Compare before/after to detect actual changes
 136→                let after = match self.jj.get_description(change_id) {
 137→                    Ok(desc) => Some(desc.trim_end().to_string()),
 138→                    Err(_) => None,
 139→                };
 140→
 141→                match (before, after) {
 142→                    (Some(b), Some(a)) if b == a => {
 143→                        self.notify_info("Description unchanged");
 144→                    }
 145→                    (Some(_), Some(_)) => {
 146→                        self.notify_success("Description updated");
 147→                    }
 148→                    _ => {
 149→                        // Could not compare (get_description failed before or after)
 150→                        self.notify_success("Describe editor closed");
 151→                    }
 152→                }
 153→            }
 154→            Ok(status) => {
 155→                self.set_error(format!(
 156→                    "Describe editor exited with error (code: {})",
 157→                    status.code().unwrap_or(-1)
 158→                ));
 159→                return;
 160→            }
 161→            Err(e) => {
 162→                self.set_error(format!("Describe failed: {}", e));
 163→                return;
 164→            }
 165→        }
 166→
 167→        // Refresh views (only on success — refresh_log clears error_message)
 168→        self.mark_dirty_and_refresh_current(DirtyFlags::log());
 169→    }
 170→
 171→    /// Execute describe operation
 172→    pub(crate) fn execute_describe(&mut self, change_id: &str, message: &str) {
 173→        let result = self.jj.describe(change_id, message);
 174→        self.run_jj_action(
 175→            result,
 176→            "Failed to update description",
 177→            "Description updated",
 178→            DirtyFlags::log(),
 179→        );
 180→    }
 181→
 182→    /// Execute edit operation (set working-copy to specified change)
 183→    pub(crate) fn execute_edit(&mut self, change_id: &str) {
 184→        let short_id = &change_id[..8.min(change_id.len())];
 185→        let msg = format!("Now editing: {}", short_id);
 186→        let result = self.jj.edit(change_id);
 187→        self.run_jj_action(result, "Failed to edit", &msg, DirtyFlags::log_and_status());
 188→    }
 189→
 190→    /// Execute new change operation
 191→    pub(crate) fn execute_new_change(&mut self) {
 192→        let result = self.jj.new_change();
 193→        self.run_jj_action(
 194→            result,
 195→            "Failed to create change",
 196→            "Created new change",
 197→            DirtyFlags::log_and_status(),
 198→        );
 199→    }
 200→
 201→    /// Execute new change from specified parent
 202→    pub(crate) fn execute_new_change_from(&mut self, parent_id: &str, display_name: &str) {
 203→        let msg = format!("Created new change from {}", display_name);
 204→        let result = self.jj.new_change_from(parent_id);
 205→        self.run_jj_action(
 206→            result,
 207→            "Failed to create change",
 208→            &msg,
 209→            DirtyFlags::log_and_status(),
 210→        );
 211→    }
 212→
 213→    /// Execute commit operation (describe current change + create new change)
 214→    pub(crate) fn execute_commit(&mut self, message: &str) {
 215→        let result = self.jj.commit(message);
 216→        self.run_jj_action(
 217→            result,
 218→            "Commit failed",
 219→            "Changes committed",
 220→            DirtyFlags::log_and_status(),
 221→        );
 222→    }
 223→
 224→    /// Execute squash into target (requires terminal control transfer)
 225→    ///
 226→    /// jj squash --from/--into may open an editor when both source and destination
 227→    /// have non-empty descriptions. Temporarily exits TUI mode to allow editor interaction.
 228→    pub(crate) fn execute_squash_into(&mut self, source: &str, destination: &str) {
 229→        use crate::jj::constants::ROOT_CHANGE_ID;
 230→
 231→        // Guard: cannot squash root commit (has no parent to receive changes from)
 232→        if source == ROOT_CHANGE_ID {
 233→            self.notify_info("Cannot squash: root commit has no parent");
 234→            return;
 235→        }
 236→
 237→        let _guard = suspend_tui();
 238→
 239→        // Run jj squash --from --into (blocking, interactive)
 240→        let result = self.jj.squash_into_interactive(source, destination);
 241→
 242→        // 4. Handle result (io::Result<ExitStatus>)
 243→        match result {
 244→            Ok(status) if status.success() => {
 245→                let src_short = &source[..8.min(source.len())];
 246→                let dst_short = &destination[..8.min(destination.len())];
 247→                self.notify_success(format!(
 248→                    "Squashed {} into {} (undo: u)",
 249→                    src_short, dst_short
 250→                ));
 251→            }
 252→            Ok(_) => {
 253→                // Non-zero exit (user cancelled editor, or jj error)
 254→                self.notify_info("Squash cancelled or failed");
 255→            }
 256→            Err(e) => {
 257→                // IO error (command not found, etc.)
 258→                self.set_error(format!("Squash failed: {}", e));
 259→            }
 260→        }
 261→
 262→        // 5. Refresh views
 263→        self.mark_dirty_and_refresh_current(DirtyFlags::log_and_status());
 264→    }
