 465→    /// Parse jj next/prev success output to notification message
 466→    fn parse_next_prev_message(output: &str, direction: &str) -> String {
 467→        let trimmed = output.trim();
 468→        if trimmed.is_empty() {
 469→            format!("Moved {} successfully", direction)
 470→        } else {
 471→            let first_line = trimmed.lines().next().unwrap_or(trimmed);
 472→            format!("Moved {}: {}", direction, first_line)
 473→        }
 474→    }
