 476→    /// Format next/prev error message for user
 477→    fn format_next_prev_error(error: &crate::jj::JjError, direction: &str) -> String {
 478→        let err_str = error.to_string();
 479→        if err_str.contains("more than one child") || err_str.contains("more than one parent") {
 480→            format!(
 481→                "Cannot move {}: multiple {}. Use 'e' to edit a specific revision.",
 482→                direction,
 483→                if direction == "next" {
 484→                    "children"
 485→                } else {
 486→                    "parents"
 487→                }
 488→            )
 489→        } else if err_str.contains("No descendant") || err_str.contains("no child") {
 490→            "Already at the newest change".to_string()
 491→        } else if err_str.contains("No ancestor") || err_str.contains("no parent") {
 492→            "Already at the root".to_string()
 493→        } else {
 494→            format!("Move {} failed: {}", direction, err_str)
 495→        }
 496→    }
