 498→    /// Execute `jj duplicate <change_id>` and refresh log
 499→    ///
 500→    /// Parses the output to extract the new change ID, refreshes the log,
 501→    /// and moves focus to the duplicated change.
 502→    pub(crate) fn duplicate(&mut self, change_id: &str) {
 503→        match self.jj.duplicate(change_id) {
 504→            Ok(output) => {
 505→                // Parse new change_id from output
 506→                let new_change_id = Self::parse_duplicate_output(&output);
 507→
 508→                // Refresh log first (before notification)
 509→                self.mark_dirty_and_refresh_current(DirtyFlags::log());
 510→
 511→                // If refresh_log failed, don't show success notification
 512→                if self.error_message.is_some() {
 513→                    return;
 514→                }
 515→
 516→                // Move focus to duplicated change + build notification
 517→                match new_change_id {
 518→                    Some(ref new_id) => {
 519→                        let short = &new_id[..new_id.len().min(8)];
 520→                        if self.log_view.select_change_by_prefix(new_id) {
 521→                            self.notification =
 522→                                Some(Notification::success(format!("Duplicated as {}", short)));
 523→                        } else {
 524→                            self.notify_success(format!(
 525→                                "Duplicated as {} (not in current revset)",
 526→                                short
 527→                            ));
 528→                        }
 529→                    }
 530→                    None => {
 531→                        self.notification =
 532→                            Some(Notification::success("Duplicated successfully".to_string()));
 533→                    }
 534→                }
 535→            }
 536→            Err(e) => {
 537→                self.set_error(format!("Duplicate failed: {}", e));
 538→            }
 539→        }
 540→    }
