 542→    /// Parse the new change ID from `jj duplicate` output
 543→    ///
 544→    /// Output format: "Duplicated <commit_id> as <new_change_id> <new_commit_id> <description>"
 545→    fn parse_duplicate_output(output: &str) -> Option<String> {
 546→        for line in output.lines() {
 547→            if let Some(rest) = line.strip_prefix("Duplicated ") {
 548→                let parts: Vec<&str> = rest.splitn(4, ' ').collect();
 549→                // parts[0] = commit_id, parts[1] = "as", parts[2] = new_change_id
 550→                if parts.len() >= 3 && parts[1] == "as" {
 551→                    return Some(parts[2].to_string());
 552→                }
 553→            }
 554→        }
 555→        None
 556→    }
