 671→                            value: "__all_remotes__".to_string(),
 672→                            selected: false,
 673→                        },
 674→                    ];
 675→                    for remote in &remotes {
 676→                        items.push(SelectItem {
 677→                            label: remote.clone(),
 678→                            value: remote.clone(),
 679→                            selected: false,
 680→                        });
 681→                    }
 682→                    items.push(SelectItem {
 683→                        label: "Specific branch...".to_string(),
 684→                        value: "__branch__".to_string(),
 685→                        selected: false,
 686→                    });
 687→                    self.active_dialog = Some(Dialog::select_single(
