 842→    pub(crate) fn execute_resolve_external(&mut self, file_path: &str) {
 843→        let (change_id, is_wc) = match self.resolve_view {
 844→            Some(ref v) => (v.change_id.clone(), v.is_working_copy),
 845→            None => return,
 846→        };
 847→
 848→        if !is_wc {
 849→            self.notify_warning("External merge tool only works for working copy (@)");
 850→            return;
 851→        }
 852→
 853→        let _guard = suspend_tui();
 854→
 855→        // Run jj resolve (blocking)
 856→        let result = self.jj.resolve_interactive(file_path, Some(&change_id));
 857→
 858→        // 4. Handle result
 859→        match result {
 860→            Ok(status) if status.success() => {
 861→                self.notify_success(format!("Resolved {}", file_path));
 862→            }
 863→            Ok(_) => {
 864→                self.notify_info("Resolve cancelled or failed");
 865→            }
 866→            Err(e) => {
 867→                self.set_error(format!("Resolve failed: {}", e));
 868→            }
 869→        }
 870→
 871→        // 5. Refresh resolve list
 872→        self.refresh_resolve_list(&change_id, is_wc);
 873→    }
