 875→    /// Execute rebase with specified mode
 876→    ///
 877→    /// Supports five modes:
 878→    /// - `Revision` (`-r`): Move single change, descendants rebased onto parent
 879→    /// - `Source` (`-s`): Move change and all descendants together
 880→    /// - `Branch` (`-b`): Move entire branch relative to destination's ancestors
 881→    /// - `InsertAfter` (`-A`): Insert change after target in history
 882→    /// - `InsertBefore` (`-B`): Insert change before target in history
 883→    ///
 884→    /// When `skip_emptied` is true, `--skip-emptied` is appended.
 885→    /// On unsupported flag errors, retries without the flag or shows guidance.
 886→    pub(crate) fn execute_rebase(
 887→        &mut self,
 888→        source: &str,
 889→        destination: &str,
 890→        mode: RebaseMode,
 891→        skip_emptied: bool,
 892→        use_revset: bool,
 893→    ) {
 894→        // Prevent rebasing to self (skip for revset — let jj validate)
 895→        if !use_revset && source == destination {
 896→            self.notify_warning("Cannot rebase to itself");
 897→            return;
 898→        }
 899→
 900→        let extra_flags: Vec<&str> = if skip_emptied {
 901→            vec![crate::jj::constants::flags::SKIP_EMPTIED]
 902→        } else {
 903→            vec![]
 904→        };
 905→
 906→        let result = self
 907→            .jj
 908→            .rebase_unified(mode, source, destination, &extra_flags);
 909→
 910→        match result {
 911→            Ok(output) => {
 912→                self.notify_rebase_success(&output, destination, mode, skip_emptied);
 913→            }
 914→            Err(e) => {
 915→                let err_msg = format!("{}", e);
 916→
 917→                if skip_emptied && is_rebase_flag_unsupported(&err_msg) {
 918→                    // --skip-emptied (or mode flag) caused failure, retry without it
 919→                    let retry = self.jj.rebase_unified(mode, source, destination, &[]);
 920→                    match retry {
 921→                        Ok(output) => {
 922→                            self.notify_rebase_success(&output, destination, mode, false);
 923→                            // Append skip-emptied note, preserving severity
 924→                            // (e.g., Warning for conflicts must not be downgraded to Info)
 925→                            if let Some(existing) = self.notification.take() {
 926→                                let new_msg = format!(
 927→                                    "{} (--skip-emptied not supported, empty commits may remain)",
 928→                                    existing.message
 929→                                );
 930→                                // Preserves original notification kind (success/info/warning)
 931→                                self.notification = Some(Notification::new(new_msg, existing.kind));
 932→                            }
 933→                        }
 934→                        Err(e2) => {
 935→                            // Retry also failed — if mode is Branch and error is still
 936→                            // "unsupported flag", the real issue is -b not being supported
 937→                            let retry_msg = format!("{}", e2);
 938→                            if mode == RebaseMode::Branch && is_rebase_flag_unsupported(&retry_msg)
 939→                            {
 940→                                self.notify_warning(
 941→                                    "Branch mode (-b) not supported in this jj version. Use Source mode (-s) instead.",
 942→                                );
 943→                            } else {
 944→                                self.set_error(format!("Rebase failed: {}", e2));
 945→                            }
 946→                        }
 947→                    }
 948→                } else if is_rebase_flag_unsupported(&err_msg) {
 949→                    // No skip_emptied — flag unsupported (e.g., -b not supported)
 950→                    if mode == RebaseMode::Branch {
 951→                        self.notify_warning(
 952→                            "Branch mode (-b) not supported in this jj version. Use Source mode (-s) instead.",
 953→                        );
 954→                    } else {
 955→                        self.set_error(format!("Rebase failed: {}", e));
 956→                    }
 957→                } else {
 958→                    self.set_error(format!("Rebase failed: {}", e));
 959→                }
 960→            }
 961→        }
 962→    }
 963→
 964→    /// Build and set notification for successful rebase
 965→    fn notify_rebase_success(
 966→        &mut self,
 967→        output: &str,
 968→        destination: &str,
 969→        mode: RebaseMode,
 970→        skip_emptied: bool,
 971→    ) {
 972→        self.mark_dirty_and_refresh_current(DirtyFlags::log_and_status());
 973→
 974→        let skip_suffix = if skip_emptied {
 975→            " (empty commits skipped)"
 976→        } else {
 977→            ""
 978→        };
 979→
 980→        // Unified conflict detection from jj output
 981→        let has_conflict = output.to_lowercase().contains("conflict");
 982→        let notification = if has_conflict {
 983→            Notification::warning("Rebased with conflicts - resolve with jj resolve")
 984→        } else {
 985→            let msg = match mode {
 986→                RebaseMode::Revision => format!("Rebased successfully{}", skip_suffix),
 987→                RebaseMode::Source => {
 988→                    format!("Rebased source and descendants successfully{}", skip_suffix)
 989→                }
 990→                RebaseMode::Branch => format!("Rebased branch successfully{}", skip_suffix),
 991→                RebaseMode::InsertAfter => {
 992→                    let short = &destination[..8.min(destination.len())];
 993→                    format!("Inserted after {} successfully{}", short, skip_suffix)
 994→                }
 995→                RebaseMode::InsertBefore => {
 996→                    let short = &destination[..8.min(destination.len())];
 997→                    format!("Inserted before {} successfully{}", short, skip_suffix)
 998→                }
 999→            };
1000→            Notification::success(msg)
1001→        };
1002→        self.notification = Some(notification);
1003→    }
