1005→    /// Update preview cache if selected change has changed.
1006→    ///
1007→    /// Called after key processing, NOT during render.
1008→    /// Skips fetch if:
1009→    /// - Preview is disabled
1010→    /// - Same change_id is already cached (cache hit)
1011→    /// - Preview auto-disabled (small terminal) — tracks pending_id for later
1012→    /// - Rapid movement detected (debounce: skip if last fetch was < 100ms ago)
1013→    pub(crate) fn update_preview_if_needed(&mut self) {
1014→        if !self.preview_enabled {
1015→            return;
1016→        }
1017→
1018→        let (current_change_id, current_commit_id) = match self.log_view.selected_change() {
1019→            Some(c) => (c.change_id.clone(), c.commit_id.clone()),
1020→            None => return, // No selection — keep cache intact
1021→        };
1022→
1023→        // Cache hit — same change_id with matching commit_id
1024→        if let Some(cached) = self.preview_cache.peek(&current_change_id)
1025→            && cached.commit_id == current_commit_id
1026→        {
1027→            self.preview_cache.touch(&current_change_id);
1028→            return;
1029→        }
1030→        // commit_id mismatch — stale, need re-fetch
1031→
1032→        // Always defer to idle tick — never block key handling with jj show.
1033→        // resolve_pending_preview() will fetch on the next poll timeout.
1034→        self.preview_pending_id = Some(current_change_id);
1035→    }
1036→
1037→    /// Actually fetch preview content via jj show
1038→    fn fetch_preview(&mut self, change_id: &str) {
1039→        self.preview_pending_id = None;
1040→
1041→        // Capture bookmarks and commit_id from the Change model
1042→        let (commit_id, bookmarks) = self
1043→            .log_view
1044→            .selected_change()
1045→            .filter(|c| c.change_id == change_id)
1046→            .map(|c| (c.commit_id.clone(), c.bookmarks.clone()))
1047→            .unwrap_or_default();
1048→
1049→        match self.jj.show(change_id) {
1050→            Ok(content) => {
1051→                self.preview_cache.insert(super::state::PreviewCacheEntry {
1052→                    change_id: change_id.to_string(),
1053→                    commit_id,
1054→                    content,
1055→                    bookmarks,
1056→                });
1057→            }
1058→            Err(_) => {
1059→                self.preview_cache.remove(change_id);
1060→            }
1061→        }
1062→    }
1063→
1064→    /// Called from the event loop idle handler (when no key is pressed).
1065→    /// Resolves any pending preview fetch that was deferred by debounce or auto-disable.
1066→    pub fn resolve_pending_preview(&mut self) {
1067→        if !self.preview_enabled || self.preview_auto_disabled {
1068→            return;
1069→        }
1070→        if let Some(pending_id) = self.preview_pending_id.take() {
1071→            // Verify the selection hasn't changed
1072→            let still_selected = self
1073→                .log_view
1074→                .selected_change()
1075→                .map(|c| c.change_id == pending_id)
1076→                .unwrap_or(false);
1077→            if still_selected {
1078→                self.fetch_preview(&pending_id);
1079→            }
1080→        }
1081→    }
