1087→    /// Copy diff content to system clipboard
1088→    pub(crate) fn copy_diff_to_clipboard(&mut self, full: bool) {
1089→        let Some(ref diff_view) = self.diff_view else {
1090→            return;
1091→        };
1092→        let change_id = diff_view.change_id.clone();
1093→        let compare_info = diff_view.compare_info.clone();
1094→
1095→        let result = if full {
1096→            if let Some(ref ci) = compare_info {
1097→                // Compare mode: jj show doesn't apply, prepend from/to metadata header
1098→                let diff = self.jj.diff_range(&ci.from.change_id, &ci.to.change_id);
1099→                diff.map(|d| {
1100→                    format!(
1101→                        "Compare: {} -> {}\nFrom: {} ({})\nTo:   {} ({})\n\n{}",
1102→                        ci.from.change_id,
1103→                        ci.to.change_id,
1104→                        ci.from.change_id,
1105→                        ci.from.description,
1106→                        ci.to.change_id,
1107→                        ci.to.description,
1108→                        d,
1109→                    )
1110→                })
1111→            } else {
1112→                self.jj.show_raw(&change_id)
1113→            }
1114→        } else {
1115→            // jj diff (diff only)
1116→            if let Some(ref ci) = compare_info {
1117→                self.jj.diff_range(&ci.from.change_id, &ci.to.change_id)
1118→            } else {
1119→                self.jj.diff_raw(&change_id)
1120→            }
1121→        };
1122→
1123→        match result {
1124→            Ok(text) => {
1125→                let line_count = text.lines().count();
1126→                match super::clipboard::copy_to_clipboard(&text) {
1127→                    Ok(()) => {
1128→                        let mode = if full { "show" } else { "diff" };
1129→                        self.notify_success(format!(
1130→                            "Copied to clipboard ({} lines, {})",
1131→                            line_count, mode
1132→                        ));
1133→                    }
1134→                    Err(e) => {
1135→                        self.set_error(e);
1136→                    }
1137→                }
1138→            }
1139→            Err(e) => {
1140→                self.set_error(format!("Failed to get diff: {}", e));
1141→            }
1142→        }
1143→    }
