1145→    /// Fetch diff content in the specified format
1146→    ///
1147→    /// Handles the difference between normal and compare modes,
1148→    /// and between ColorWords (which returns DiffContent directly via `jj show`)
1149→    /// and Stat/Git (which return String and need parsing).
1150→    fn fetch_diff_content(
1151→        &self,
1152→        change_id: &str,
1153→        format: DiffDisplayFormat,
1154→        compare: Option<&CompareInfo>,
1155→    ) -> Result<DiffContent, crate::jj::JjError> {
1156→        use crate::jj::parser::Parser;
1157→
1158→        if let Some(ci) = compare {
1159→            match format {
1160→                DiffDisplayFormat::ColorWords => self
1161→                    .jj
1162→                    .diff_range(&ci.from.change_id, &ci.to.change_id)
1163→                    .map(|o| Parser::parse_diff_body(&o)),
1164→                DiffDisplayFormat::Stat => self
1165→                    .jj
1166→                    .diff_range_stat(&ci.from.change_id, &ci.to.change_id)
1167→                    .map(|o| Parser::parse_diff_body_stat(&o)),
1168→                DiffDisplayFormat::Git => self
1169→                    .jj
1170→                    .diff_range_git(&ci.from.change_id, &ci.to.change_id)
1171→                    .map(|o| Parser::parse_diff_body_git(&o)),
1172→            }
1173→        } else {
1174→            match format {
1175→                DiffDisplayFormat::ColorWords => self.jj.show(change_id),
1176→                DiffDisplayFormat::Stat => self
1177→                    .jj
1178→                    .show_stat(change_id)
1179→                    .and_then(|o| Parser::parse_show_stat(&o)),
1180→                DiffDisplayFormat::Git => self
1181→                    .jj
1182→                    .show_git(change_id)
1183→                    .and_then(|o| Parser::parse_show_git(&o)),
1184→            }
1185→        }
1186→    }
1187→
1188→    /// Cycle the diff display format and re-fetch content
1189→    pub(crate) fn cycle_diff_format(&mut self) {
1190→        use crate::model::DiffDisplayFormat;
1191→
1192→        let Some(ref diff_view) = self.diff_view else {
1193→            return;
1194→        };
1195→
1196→        let old_format = diff_view.display_format;
1197→        let new_format = old_format.next();
1198→        let change_id = diff_view.change_id.clone();
1199→        let compare_info = diff_view.compare_info.clone();
1200→
1201→        match self.fetch_diff_content(&change_id, new_format, compare_info.as_ref()) {
1202→            Ok(content) => {
1203→                let diff_view = self.diff_view.as_mut().unwrap();
1204→                diff_view.set_content(change_id, content);
1205→                diff_view.compare_info = compare_info;
1206→                diff_view.display_format = new_format;
1207→
1208→                self.notify_info(format!(
1209→                    "Display: {} ({}/{})",
1210→                    new_format.label(),
1211→                    new_format.position(),
1212→                    DiffDisplayFormat::COUNT,
1213→                ));
1214→            }
1215→            Err(e) => {
1216→                self.set_error(format!(
1217→                    "Failed to load {} format: {}",
1218→                    new_format.label(),
1219→                    e
1220→                ));
1221→            }
1222→        }
1223→    }
1224→
1225→    /// Export diff content to a .patch file
1226→    pub(crate) fn export_diff_to_file(&mut self) {
1227→        let Some(ref diff_view) = self.diff_view else {
1228→            return;
1229→        };
1230→        let change_id = diff_view.change_id.clone();
1231→        let compare_info = diff_view.compare_info.clone();
1232→
1233→        // Determine filename and content based on mode
1234→        // Uses `jj diff --git` for git-compatible unified patch format (git apply compatible)
1235→        let (short_id, result) = if let Some(ref ci) = compare_info {
1236→            // Compare mode: use diff --git --from --to
1237→            let from_short = &ci.from.change_id[..ci.from.change_id.len().min(8)];
1238→            let to_short = &ci.to.change_id[..ci.to.change_id.len().min(8)];
1239→            let label = format!("{}_{}", from_short, to_short);
1240→            let result = self.jj.diff_range_git(&ci.from.change_id, &ci.to.change_id);
1241→            (label, result)
1242→        } else {
1243→            let short = change_id[..change_id.len().min(8)].to_string();
1244→            let result = self.jj.diff_git_raw(&change_id);
1245→            (short, result)
1246→        };
1247→
1248→        match result {
1249→            Ok(text) => {
1250→                let filename = unique_patch_filename(&short_id);
1251→                match std::fs::write(&filename, &text) {
1252→                    Ok(()) => {
1253→                        self.notification =
1254→                            Some(Notification::success(format!("Exported to {}", filename)));
1255→                    }
1256→                    Err(e) => {
1257→                        self.set_error(format!("Failed to write {}: {}", filename, e));
1258→                    }
1259→                }
1260→            }
1261→            Err(e) => {
1262→                self.set_error(format!("Failed to get diff: {}", e));
1263→            }
1264→        }
1265→    }
1266→}
1267→
1268→/// Generate a unique .patch filename, appending -1, -2, etc. if the file already exists
1269→fn unique_patch_filename(short_id: &str) -> String {
1270→    let base = format!("{}.patch", short_id);
1271→    if !std::path::Path::new(&base).exists() {
1272→        return base;
1273→    }
1274→    for i in 1.. {
1275→        let candidate = format!("{}-{}.patch", short_id, i);
1276→        if !std::path::Path::new(&candidate).exists() {
1277→            return candidate;
1278→        }
1279→    }
1280→    unreachable!()
1281→}
