1283→/// Check if a rebase error indicates an unsupported flag
1284→///
1285→/// Older jj versions may not support `--skip-emptied` or `-b`.
1286→/// Detects generic "unexpected argument" / "unrecognized" errors.
1287→fn is_rebase_flag_unsupported(err_msg: &str) -> bool {
1288→    let lower = err_msg.to_lowercase();
1289→    lower.contains("unexpected argument")
1290→        || lower.contains("unrecognized")
1291→        || lower.contains("unknown flag")
1292→        || lower.contains("unknown option")
1293→}
