  1→//! jj command executor
  2→//!
  3→//! Handles running jj commands and capturing their output.
  4→//!
  5→//! ## Concurrency rules for jj command execution
  6→//!
  7→//! - **Read-Read**: Safe to parallelize (`jj log` + `jj status` + `jj op log`, etc.)
  8→//! - **Write → Read**: Must be sequential (action must complete before refresh reads its result)
  9→//! - **Write-Write**: Must be sequential (never parallelize two write operations)
 10→//! - **Result consistency**: When parallel reads complete, apply all results to App state
 11→//!   atomically to avoid partial/inconsistent UI state.
 12→
 13→use std::path::PathBuf;
 14→use std::process::Command;
 15→
 16→use crate::model::{
 17→    AnnotationContent, Bookmark, BookmarkInfo, Change, ConflictFile, DiffContent, Operation,
 18→    RebaseMode, Status,
 19→};
 20→
 21→use super::JjError;
 22→use super::constants::{self, commands, errors, flags, resolve_flags};
 23→use super::parser::Parser;
 24→use super::template::Templates;
 25→
 26→/// Bulk push mode (repository-wide push operations)
 27→#[derive(Debug, Clone, Copy, PartialEq, Eq)]
 28→pub enum PushBulkMode {
 29→    /// Push all bookmarks (including new) — `--all`
 30→    All,
 31→    /// Push tracked bookmarks only — `--tracked`
 32→    Tracked,
 33→    /// Push deleted bookmarks — `--deleted`
 34→    Deleted,
 35→}
 36→
 37→impl PushBulkMode {
 38→    /// Return the jj CLI flag for this mode
 39→    pub fn flag(&self) -> &'static str {
 40→        match self {
 41→            Self::All => flags::ALL,
 42→            Self::Tracked => flags::TRACKED,
 43→            Self::Deleted => flags::DELETED,
 44→        }
 45→    }
 46→
 47→    /// Human-readable label for UI
 48→    pub fn label(&self) -> &'static str {
 49→        match self {
 50→            Self::All => "all bookmarks",
 51→            Self::Tracked => "tracked bookmarks",
 52→            Self::Deleted => "deleted bookmarks",
 53→        }
 54→    }
 55→}
 56→
 57→/// Executor for jj commands
 58→///
 59→/// All methods take `&self` (no mutable state), making `JjExecutor` safe to
 60→/// share across threads via `&JjExecutor`. This is verified by the compile-time
 61→/// assertion below.
 62→#[derive(Debug, Clone)]
 63→pub struct JjExecutor {
 64→    /// Path to the repository (None = current directory)
 65→    repo_path: Option<PathBuf>,
 66→}
 67→
 68→// Compile-time assertion: JjExecutor must be Sync for thread::scope sharing.
 69→// If this fails, consider wrapping in Arc or removing interior mutability.
 70→const _: () = {
 71→    const fn assert_sync<T: Sync>() {}
 72→    assert_sync::<JjExecutor>();
 73→};
 74→
 75→impl Default for JjExecutor {
 76→    fn default() -> Self {
 77→        Self::new()
 78→    }
 79→}
 80→
 81→impl JjExecutor {
 82→    /// Create a new executor for the current directory
 83→    pub fn new() -> Self {
 84→        Self { repo_path: None }
 85→    }
 86→
 87→    /// Create a new executor for a specific repository path
 88→    #[allow(dead_code)]
 89→    pub fn with_repo_path(path: PathBuf) -> Self {
 90→        Self {
 91→            repo_path: Some(path),
 92→        }
 93→    }
 94→
 95→    /// Get the repository path (for use by other impl blocks in sibling modules)
 96→    pub(crate) fn repo_path(&self) -> Option<&PathBuf> {
 97→        self.repo_path.as_ref()
 98→    }
 99→
100→    /// Run a jj command with the given arguments
101→    ///
102→    /// Automatically adds `--color=never` to ensure parseable output.
103→    pub fn run(&self, args: &[&str]) -> Result<String, JjError> {
104→        use std::process::Stdio;
105→
106→        let mut cmd = Command::new(constants::JJ_COMMAND);
107→
108→        // Add repository path if specified
109→        if let Some(ref path) = self.repo_path {
110→            cmd.arg(flags::REPO_PATH).arg(path);
111→        }
112→
113→        // Always disable color for parsing
114→        cmd.arg(flags::NO_COLOR);
115→
116→        // Add user-specified arguments
117→        cmd.args(args);
118→
119→        // Explicitly close stdin to prevent jj from waiting for input
120→        // (e.g., during snapshot warnings or interactive prompts).
121→        // Without this, Command::output() creates a pipe for stdin,
122→        // which may not signal EOF properly under raw-mode terminals.
123→        cmd.stdin(Stdio::null());
124→
125→        let output = cmd.output().map_err(|e| {
126→            if e.kind() == std::io::ErrorKind::NotFound {
127→                JjError::JjNotFound
128→            } else {
129→                JjError::IoError(e)
130→            }
131→        })?;
132→
133→        if output.status.success() {
134→            Ok(String::from_utf8_lossy(&output.stdout).into_owned())
135→        } else {
136→            let stderr = String::from_utf8_lossy(&output.stderr).into_owned();
137→            let exit_code = output.status.code().unwrap_or(-1);
138→
139→            // Check for common error patterns
140→            if stderr.contains(errors::NOT_A_REPO) {
141→                return Err(JjError::NotARepository);
142→            }
143→
144→            // jj exits with code 1 when snapshot warnings are present
145→            // (e.g., large files exceeding snapshot.max-new-file-size)
146→            // but the command itself may have succeeded.
147→            //
148→            // The snapshot is a pre-command operation; its failure does not
149→            // mean the command failed. Treat "Refused to snapshot" as
150→            // non-fatal for all commands — the proper fix is configuring
151→            // .jjignore or snapshot.max-new-file-size in the repository.
152→            let stdout = String::from_utf8_lossy(&output.stdout).into_owned();
153→            if stderr.contains("Refused to snapshot") {
154→                return Ok(stdout);
155→            }
156→
157→            Err(JjError::CommandFailed { stderr, exit_code })
158→        }
159→    }
160→
161→    /// Run `jj log` with optional revset filter (raw output)
162→    ///
163→    /// Note: Graph output is enabled to show DAG structure.
164→    /// The parser handles graph prefixes in the output.
165→    pub fn log_raw(&self, revset: Option<&str>, reversed: bool) -> Result<String, JjError> {
166→        let template = Templates::log();
167→        let mut args = vec![commands::LOG, flags::TEMPLATE, template];
168→
169→        if let Some(rev) = revset {
170→            args.push(flags::REVISION);
171→            args.push(rev);
172→            // No --limit for revset queries (preserve exploration)
173→        } else {
174→            // Default view: limit to avoid slowness on large repos
175→            args.push(flags::LIMIT);
176→            args.push(constants::DEFAULT_LOG_LIMIT);
177→        }
178→
179→        if reversed {
180→            args.push(flags::REVERSED);
181→        }
182→
183→        self.run(&args)
184→    }
185→
186→    /// Run `jj log` and parse the output into Changes
187→    pub fn log(&self, revset: Option<&str>, reversed: bool) -> Result<Vec<Change>, JjError> {
188→        let output = self.log_raw(revset, reversed)?;
189→        Parser::parse_log(&output).map_err(|e| JjError::ParseError(e.to_string()))
190→    }
191→
192→    /// Run `jj log` and parse output into Changes for current view.
193→    /// This is the preferred API for application code.
194→    pub fn log_changes(
195→        &self,
196→        revset: Option<&str>,
197→        reversed: bool,
198→    ) -> Result<Vec<Change>, JjError> {
199→        self.log(revset, reversed)
200→    }

