906→        // Note: `jj git push --dry-run` outputs to stderr, not stdout,
907→        // so we can't use the generic `run()` method here.
908→        let mut cmd = Command::new(constants::JJ_COMMAND);
909→        if let Some(ref path) = self.repo_path {
910→            cmd.arg(flags::REPO_PATH).arg(path);
911→        }
912→        cmd.arg(flags::NO_COLOR);
913→        cmd.args([
914→            commands::GIT,
915→            commands::GIT_PUSH,
916→            flags::DRY_RUN,
917→            flags::BOOKMARK_FLAG,
918→            bookmark_name,
