920→
921→        let output = cmd.output().map_err(|e| {
922→            if e.kind() == std::io::ErrorKind::NotFound {
923→                JjError::JjNotFound
924→            } else {
925→                JjError::IoError(e)
926→            }
927→        })?;
928→
929→        if output.status.success() {
930→            Ok(String::from_utf8_lossy(&output.stderr).into_owned())
931→        } else {
932→            let stderr = String::from_utf8_lossy(&output.stderr).into_owned();
933→            let exit_code = output.status.code().unwrap_or(-1);
934→            Err(JjError::CommandFailed { stderr, exit_code })
