  8→impl App {
  9→    /// Handle dialog result
 10→    ///
 11→    /// Called when a dialog is closed.
 12→    ///
 13→    /// Implementation order (important):
 14→    /// 1. Clone callback_id from active_dialog
 15→    /// 2. Set active_dialog to None
 16→    /// 3. Match on callback and result
 17→    pub(crate) fn handle_dialog_result(&mut self, result: DialogResult) {
 18→        let callback = self.active_dialog.as_ref().map(|d| d.callback_id.clone());
 19→        self.active_dialog = None;
 20→
 21→        let Some(callback) = callback else { return };
 22→
 23→        match result {
 24→            DialogResult::Cancelled => self.handle_dialog_cancel(callback),
 25→            DialogResult::Confirmed(values) => match callback {
 26→                // Git Push
 27→                DialogCallback::GitPush
 28→                | DialogCallback::GitPushChange { .. }
 29→                | DialogCallback::GitPushRemoteSelect
 30→                | DialogCallback::GitPushModeSelect { .. }
 31→                | DialogCallback::GitPushBulkConfirm { .. }
 32→                | DialogCallback::GitPushRevisions { .. }
 33→                | DialogCallback::GitPushMultiBookmarkMode { .. } => {
 34→                    self.handle_git_push_dialog(callback, values);
 35→                }
 36→                // Git Fetch
 37→                DialogCallback::GitFetch | DialogCallback::GitFetchBranch => {
 38→                    self.handle_git_fetch_dialog(callback, values);
 39→                }
 40→                // Bookmark
 41→                DialogCallback::DeleteBookmarks
 42→                | DialogCallback::MoveBookmark { .. }
 43→                | DialogCallback::BookmarkJump
 44→                | DialogCallback::BookmarkForget
 45→                | DialogCallback::BookmarkMoveToWc { .. }
 46→                | DialogCallback::BookmarkMoveBackwards { .. } => {
 47→                    self.handle_bookmark_dialog(callback, values);
 48→                }
 49→                // Misc
 50→                DialogCallback::OpRestore
 51→                | DialogCallback::Track
 52→                | DialogCallback::RestoreFile { .. }
 53→                | DialogCallback::RestoreAll
 54→                | DialogCallback::Revert { .. }
 55→                | DialogCallback::SimplifyParents { .. }
 56→                | DialogCallback::Parallelize { .. } => {
 57→                    self.handle_misc_dialog(callback, values);
 58→                }
 59→            },
 60→        }
 61→    }
 62→
 63→    /// Handle dialog cancellation — clean up any pending state
 64→    fn handle_dialog_cancel(&mut self, callback: DialogCallback) {
 65→        match callback {
 66→            DialogCallback::GitPush => {
 67→                self.pending_push_bookmarks.clear();
 68→                self.push_target_remote = None;
 69→            }
 70→            DialogCallback::GitPushChange { .. }
 71→            | DialogCallback::GitPushRemoteSelect
 72→            | DialogCallback::GitPushModeSelect { .. }
 73→            | DialogCallback::GitPushBulkConfirm { .. }
 74→            | DialogCallback::GitPushRevisions { .. }
 75→            | DialogCallback::GitPushMultiBookmarkMode { .. } => {
 76→                self.push_target_remote = None;
 77→            }
 78→            DialogCallback::BookmarkForget => {
 79→                self.pending_forget_bookmark = None;
 80→            }
 81→            // All others: no cleanup needed on cancel
 82→            DialogCallback::DeleteBookmarks
 83→            | DialogCallback::MoveBookmark { .. }
 84→            | DialogCallback::OpRestore
 85→            | DialogCallback::Track
 86→            | DialogCallback::BookmarkJump
 87→            | DialogCallback::GitFetch
 88→            | DialogCallback::GitFetchBranch
 89→            | DialogCallback::BookmarkMoveToWc { .. }
 90→            | DialogCallback::BookmarkMoveBackwards { .. }
 91→            | DialogCallback::RestoreFile { .. }
 92→            | DialogCallback::RestoreAll
 93→            | DialogCallback::Revert { .. }
 94→            | DialogCallback::SimplifyParents { .. }
 95→            | DialogCallback::Parallelize { .. } => {}
 96→        }
 97→    }
 98→
 99→    /// Handle confirmed Git Push dialog results
100→    fn handle_git_push_dialog(&mut self, callback: DialogCallback, values: Vec<String>) {
101→        match callback {
102→            DialogCallback::GitPush => {
103→                if values.is_empty() {
104→                    let bookmarks = std::mem::take(&mut self.pending_push_bookmarks);
105→                    self.execute_push(&bookmarks);
106→                } else {
107→                    self.execute_push(&values);
108→                }
109→            }
110→            DialogCallback::GitPushChange { change_id } => {
111→                self.execute_push_change(&change_id);
112→            }
113→            DialogCallback::GitPushRemoteSelect => {
114→                if let Some(remote) = values.first() {
115→                    self.push_target_remote = Some(remote.clone());
116→                    self.start_push();
117→                }
118→            }
119→            DialogCallback::GitPushModeSelect { change_id } => {
120→                match values.first().map(|s| s.as_str()) {
121→                    Some("change") => self.start_push_change(&change_id),
122→                    Some("all") => self.start_push_bulk(PushBulkMode::All),
123→                    Some("tracked") => self.start_push_bulk(PushBulkMode::Tracked),
124→                    Some("deleted") => self.start_push_bulk(PushBulkMode::Deleted),
125→                    _ => {}
126→                }
127→            }
128→            DialogCallback::GitPushBulkConfirm { mode, remote } => {
129→                self.execute_push_bulk(mode, remote.as_deref());
130→            }
131→            DialogCallback::GitPushRevisions {
132→                change_id,
133→                bookmarks,
134→            } => {
135→                self.execute_push_revisions(&change_id, &bookmarks);
136→            }
137→            DialogCallback::GitPushMultiBookmarkMode {
138→                change_id,
139→                bookmarks,
140→            } => match values.first().map(|s| s.as_str()) {
141→                Some("revisions") => self.start_push_revisions(&change_id, &bookmarks),
142→                Some("individual") => self.show_individual_bookmark_select(&change_id, &bookmarks),
143→                _ => {}
144→            },
145→            _ => {}
146→        }
147→    }
